  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→  getSessionRaw,
 28→} from "../db";
 29→import { computeWorkspacePath } from "../middleware/workspace-loader";
 30→import { writeUserMessage } from "./message-writer";
 31→import { getConnection } from "./ws.service";
 32→import {
 33→  QUERY_RESOURCES,
 34→  MUTATION_NAMES,
 35→  COMMAND_NAMES,
 36→  type MutationName,
 37→  type CommandName,
 38→  type QueryResource,
 39→  type QServerFrame,
 40→} from "../../../shared/types/query-protocol";
 41→
 42→// ---- Subscription State ----
 43→
 44→type QueryParams = Record<string, unknown>;
 45→
 46→interface ResourceFrameInput {
 47→  id: string;
 48→  resource: string;
 49→  params: QueryParams;
 50→}
 51→
 52→interface UnsubscribeFrameInput {
 53→  id: string;
 54→}
 55→
 56→interface MutateFrameInput {
 57→  id: string;
 58→  action: string;
 59→  params: QueryParams;
 60→}
 61→
 62→interface CommandFrameInput {
 63→  id: string;
 64→  command: string;
 65→  params: QueryParams;
 66→}
 67→
 68→interface Sub {
 69→  id: string;
 70→  resource: QueryResource;
 71→  params: QueryParams;
 72→}
 73→
 74→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 75→const subs = new Map<string, Map<string, Sub>>();
 76→
 77→/** For messages: track last seen seq per subscription for delta push.
 78→ *  Key: `${connectionId}:${subId}` → lastSeq */
 79→const messageCursors = new Map<string, number>();
 80→
 81→// ---- Public API ----
 82→
 83→/**
 84→ * Handle an incoming q:* frame from an authenticated connection.
 85→ * Registered as onQueryFrame in ws.service protocol handlers.
 86→ */
 87→export function handleFrame(connectionId: string, msg: QueryParams): void {
 88→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 89→
 90→  try {
 91→    match(type)
 92→      .with("q:request", () => {
 93→        handleRequest(connectionId, parseResourceFrame(msg));
 94→      })
 95→      .with("q:subscribe", () => {
 96→        handleSubscribe(connectionId, parseResourceFrame(msg));
 97→      })
 98→      .with("q:unsubscribe", () => {
 99→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
100→      })
101→      .with("q:mutate", () => {
102→        handleMutate(connectionId, parseMutateFrame(msg));
103→      })
104→      .with("q:command", () => {
105→        handleCommand(connectionId, parseCommandFrame(msg));
106→      })
107→      .otherwise(() => {
108→        sendFrame(connectionId, {
109→          type: "q:error",
110→          id: getFrameId(msg),
111→          code: "UNKNOWN_FRAME",
112→          message: `Unknown query frame type: ${type}`,
113→        });
114→      });
115→  } catch (err) {
116→    sendFrame(connectionId, {
117→      type: "q:error",
118→      id: getFrameId(msg),
119→      code: "INVALID_FRAME",
120→      message: err instanceof Error ? err.message : "Invalid query frame",
121→    });
122→  }
123→}
124→
125→/** Remove all subscriptions for a connection (cleanup on disconnect). */
126→export function removeSubs(connectionId: string): void {
127→  const connSubs = subs.get(connectionId);
128→  if (connSubs) {
129→    for (const [subId, sub] of connSubs) {
130→      if (sub.resource === "messages") {
131→        messageCursors.delete(`${connectionId}:${subId}`);
132→      }
133→    }
134→    subs.delete(connectionId);
135→  }
136→}
137→
138→/** Optional context for targeted invalidation (e.g., which sessions changed). */
139→interface InvalidateContext {
140→  sessionIds?: string[];
141→}
142→
143→/**
144→ * Push-first invalidation: re-run queries for active subscribers and push
145→ * fresh snapshots or deltas.
146→ *
147→ * Messages use q:delta (cursor-based) instead of full snapshots.
148→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
149→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
150→ */
151→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
152→  if (resources.includes("stats")) {
153→    resetStatsCache();
154→  }
155→
156→  // Phase 1: Push fresh data to active subscribers
157→  for (const [connectionId, connSubs] of subs) {
158→    if (!getConnection(connectionId)) {
159→      removeSubs(connectionId);
160→      continue;
161→    }
162→
163→    for (const [subId, sub] of connSubs) {
164→      if (!resources.includes(sub.resource)) continue;
165→
166→      if (sub.resource === "messages") {
167→        // Messages: push delta (new messages since last cursor)
168→        pushMessageDelta(connectionId, subId, sub.params);
169→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
170→        // Workspaces with session context: try targeted delta
171→        try {
172→          const db = getDatabase();
173→          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
174→          const allowedStates = new Set(stateFilter.split(",").map(s => s.trim()));
175→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds)
176→            .filter(ws => allowedStates.has(ws.state));
177→          if (changedWorkspaces.length > 0) {
178→            const withPaths = changedWorkspaces.map(ws => ({
179→              ...ws,
180→              workspace_path: computeWorkspacePath(ws),
181→            }));
182→            sendFrame(connectionId, {
183→              type: "q:delta",
184→              id: subId,
185→              upserted: withPaths,
186→            });
187→          } else {
188→            // Session IDs didn't match any workspaces — fall back to full snapshot
189→            const data = runQuery(sub.resource, sub.params);
190→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
191→          }
192→        } catch (err) {
193→          // Delta lookup failed — fall back to full snapshot
194→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
195→          try {
196→            const data = runQuery(sub.resource, sub.params);
197→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
198→          } catch (snapErr) {
199→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
200→          }
201→        }
202→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
203→        // Session with context: only push if this subscription's session is in the changed set
204→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
205→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
206→          try {
207→            const data = runQuery(sub.resource, sub.params);
208→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
209→          } catch (err) {
210→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
211→          }
212→        }
213→        // If session not in changed set, skip the push
214→      } else {
215→        // Other resources: push full snapshot
216→        try {
217→          const data = runQuery(sub.resource, sub.params);
218→          sendFrame(connectionId, {
219→            type: "q:snapshot",
220→            id: subId,
221→            data,
222→          });
223→        } catch (err) {
224→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
225→        }
226→      }
227→    }
228→  }
229→
230→}
231→
232→// ---- Frame Handlers ----
233→
234→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
235→  const { id, resource, params } = msg;
236→
237→  try {
238→    const typedResource = toQueryResource(resource);
239→    const data = runQuery(typedResource, params);
240→    sendFrame(connectionId, { type: "q:response", id, data });
241→  } catch (err) {
242→    sendFrame(connectionId, {
243→      type: "q:error",
244→      id,
245→      code: "QUERY_ERROR",
246→      message: err instanceof Error ? err.message : "Query failed",
247→    });
248→  }
249→}
250→
251→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
252→  const { id, resource, params } = msg;
253→
254→  // Validate resource upfront — fail fast before running query
255→  const typedResource = toQueryResource(resource);
256→
257→  // Send initial snapshot — only register subscription if query succeeds
258→  // (avoids zombie subscriptions when runQuery throws on invalid params)
259→  try {
260→    const data = runQuery(typedResource, params);
261→
262→    // Get or create subscription map for this connection
263→    let connSubs = subs.get(connectionId);
264→    if (!connSubs) {
265→      connSubs = new Map();
266→      subs.set(connectionId, connSubs);
267→    }
268→
269→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
270→    connSubs.set(id, { id, resource: typedResource, params });
271→
272→    // For messages: initialize cursor to current max seq
273→    if (typedResource === "messages") {
274→      const sessionId = readStringParam(params, "sessionId");
275→      const cursorKey = `${connectionId}:${id}`;
276→      if (sessionId) {
277→        try {
278→          const db = getDatabase();
279→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
280→        } catch {
281→          messageCursors.set(cursorKey, 0);
282→        }
283→      }
284→    }
285→
286→    sendFrame(connectionId, { type: "q:snapshot", id, data });
287→  } catch (err) {
288→    sendFrame(connectionId, {
289→      type: "q:error",
290→      id,
291→      code: "SUBSCRIBE_ERROR",
292→      message: err instanceof Error ? err.message : "Subscribe failed",
293→    });
294→  }
295→}
296→
297→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
298→  const { id } = msg;
299→
300→  const connSubs = subs.get(connectionId);
301→  if (!connSubs) return;
302→
303→  const sub = connSubs.get(id);
304→  if (sub) {
305→    // Clean up message cursor
306→    if (sub.resource === "messages") {
307→      messageCursors.delete(`${connectionId}:${id}`);
308→    }
309→    connSubs.delete(id);
310→    if (connSubs.size === 0) subs.delete(connectionId);
311→  }
312→}
313→
314→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
315→  const { id, action, params } = msg;
316→
317→  try {
318→    const result = runMutation(action, params);
319→    sendFrame(connectionId, {
320→      type: "q:mutate_result",
321→      id,
322→      success: true,
323→      data: result,
324→    });
325→  } catch (err) {
326→    sendFrame(connectionId, {
327→      type: "q:mutate_result",
328→      id,
329→      success: false,
330→      error: err instanceof Error ? err.message : "Mutation failed",
331→    });
332→  }
333→}
334→
335→function handleCommand(connectionId: string, msg: CommandFrameInput): void {
336→  const { id, command, params } = msg;
337→
338→  try {
339→    const result = runCommand(command, params);
340→    sendFrame(connectionId, {
341→      type: "q:command_ack",
342→      id,
343→      accepted: true,
344→      ...result,
345→    } satisfies QServerFrame);
346→  } catch (err) {
347→    sendFrame(connectionId, {
348→      type: "q:command_ack",
349→      id,
350→      accepted: false,
351→      error: err instanceof Error ? err.message : "Command failed",
352→    } satisfies QServerFrame);
353→  }
354→}
355→
356→// ---- Command Dispatch ----
357→
358→function runCommand(command: string, params: QueryParams): { commandId?: string } {
359→  const typedCommand = toCommandName(command);
360→
361→  return match(typedCommand)
362→    .with("sendMessage", () => {
363→      const sessionId = readStringParam(params, "sessionId");
364→      const content = readStringParam(params, "content");
365→      const model = readStringParam(params, "model");
366→      if (!sessionId || !content) {
367→        throw new Error("sendMessage requires sessionId and content");
368→      }
369→
370→      const result = writeUserMessage(sessionId, content, model);
371→      if (!result.success) throw new Error(result.error);
372→      invalidate(["workspaces", "sessions", "session", "messages", "stats"], { sessionIds: [sessionId] });
373→      return { commandId: result.messageId };
374→    })
375→    .with("stopSession", () => {
376→      const sessionId = readStringParam(params, "sessionId");
377→      if (!sessionId) throw new Error("stopSession requires sessionId");
378→
379→      const db = getDatabase();
380→      const session = getSessionRaw(db, sessionId);
381→      if (!session) throw new Error("Session not found");
382→
383→      db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(sessionId);
384→      invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
385→      return {};
386→    })
387→    .exhaustive();
388→}
389→
390→// ---- Query Dispatch ----
391→
392→function runQuery(resource: QueryResource, params: QueryParams): unknown {
393→  const db = getDatabase();
394→
395→  return match(resource)
396→    .with("workspaces", () => {
397→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
398→      const state = readStringParam(params, "state") ?? "ready,initializing";
399→      const workspaces = getWorkspacesByRepo(db, state);
400→
401→      const grouped: Record<string, { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }> = {};
402→      workspaces.forEach(workspace => {
403→        const repoId = workspace.repository_id || "unknown";
404→        if (!grouped[repoId]) {
405→          grouped[repoId] = {
406→            repo_id: repoId,
407→            repo_name: workspace.repo_name || "Unknown",
408→            sort_order: workspace.repo_sort_order ?? 999,
409→            workspaces: [],
410→          };
411→        }
412→        grouped[repoId].workspaces.push({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
413→      });
414→
415→      // Backfill repos that have no matching workspaces (e.g. all archived)
416→      const allRepos = getAllRepositorySummaries(db);
417→      for (const repo of allRepos) {
418→        if (!grouped[repo.id]) {
419→          grouped[repo.id] = {
420→            repo_id: repo.id,
421→            repo_name: repo.name,
422→            sort_order: repo.sort_order ?? 999,
423→            workspaces: [],
424→          };
425→        }
426→      }
427→
428→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
429→    })
430→    .with("stats", () => getStats(db))
431→    .with("sessions", () => {
432→      const workspaceId = readStringParam(params, "workspaceId");
433→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
434→      return getSessionsByWorkspaceId(db, workspaceId);
435→    })
436→    .with("session", () => {
437→      const sessionId = readStringParam(params, "sessionId");
438→      if (!sessionId) throw new Error("session requires sessionId param");
439→      return getSessionById(db, sessionId);
440→    })
441→    .with("messages", () => {
442→      const sessionId = readStringParam(params, "sessionId");
443→      if (!sessionId) throw new Error("messages requires sessionId param");
444→
445→      const rows = getMessages(db, sessionId, {
446→        limit: readNumberParam(params, "limit") ?? 50,
447→        before: readNumberParam(params, "before"),
448→        after: readNumberParam(params, "after"),
449→      });
450→
451→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
452→      const hasNewer = rows.length > 0
453→        ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq)
454→        : false;
455→
456→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
457→    })
458→    .exhaustive();
459→}
460→
461→// ---- Mutation Dispatch ----
462→
463→function runMutation(action: string, params: QueryParams): unknown {
464→  const typedAction = toMutationName(action);
465→
466→  return match(typedAction)
467→    .with("archiveWorkspace", () => {
468→      const db = getDatabase();
469→      const workspaceId = readStringParam(params, "workspaceId");
470→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
471→
472→      const workspace = getWorkspaceRaw(db, workspaceId);
473→      if (!workspace) throw new Error("Workspace not found");
474→
475→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
476→      invalidate(["workspaces", "stats"]);
477→      return { success: true };
478→    })
479→    .with("updateWorkspaceTitle", () => {
480→      const db = getDatabase();
481→      const workspaceId = readStringParam(params, "workspaceId");
482→      const title = readStringParam(params, "title");
483→      if (!workspaceId || title === undefined) {
484→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
485→      }
486→
487→      const workspace = getWorkspaceRaw(db, workspaceId);
488→      if (!workspace) throw new Error("Workspace not found");
489→
490→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
491→      invalidate(["workspaces"]);
492→      return { success: true };
493→    })
494→    .exhaustive();
495→}
496→
497→// ---- Message Delta Push ----
498→
499→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
500→  const sessionId = readStringParam(params, "sessionId");
501→  if (!sessionId) return;
502→
503→  const cursorKey = `${connectionId}:${subId}`;
504→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
505→
506→  try {
507→    const db = getDatabase();
508→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
509→
510→    if (newMessages.length === 0) return;
511→
512→    const maxSeq = newMessages[newMessages.length - 1].seq;
513→    messageCursors.set(cursorKey, maxSeq);
514→
515→    sendFrame(connectionId, {
516→      type: "q:delta",
517→      id: subId,
518→      upserted: newMessages,
519→      cursor: maxSeq,
520→    });
521→  } catch (err) {
522→    console.error(`[QueryEngine] Message delta push failed:`, err);
523→  }
524→}
525→
526→// ---- Helpers ----
527→
528→function sendFrame(connectionId: string, frame: QServerFrame): void {
529→  const conn = getConnection(connectionId);
530→  if (!conn) return;
531→  try {
532→    conn.ws.send(JSON.stringify(frame));
533→  } catch {
534→    // Connection may have closed
535→  }
536→}
537→
538→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
539→  return {
540→    id: requireString(msg.id, "id"),
541→    resource: requireString(msg.resource, "resource"),
542→    params: getParams(msg.params),
543→  };
544→}
545→
546→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
547→  return {
548→    id: requireString(msg.id, "id"),
549→  };
550→}
551→
552→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
553→  return {
554→    id: requireString(msg.id, "id"),
555→    action: requireString(msg.action, "action"),
556→    params: getParams(msg.params),
557→  };
558→}
559→
560→function getParams(value: unknown): QueryParams {
561→  if (value == null) return {};
562→  if (isRecord(value)) return value;
563→  throw new Error("Frame params must be an object");
564→}
565→
566→function requireString(value: unknown, field: string): string {
567→  if (typeof value !== "string") {
568→    throw new Error(`Frame requires string ${field}`);
569→  }
570→  return value;
571→}
572→
573→function getFrameId(msg: QueryParams): string {
574→  return typeof msg.id === "string" ? msg.id : "unknown";
575→}
576→
577→function isRecord(value: unknown): value is QueryParams {
578→  return typeof value === "object" && value !== null && !Array.isArray(value);
579→}
580→
581→function readStringParam(params: QueryParams, key: string): string | undefined {
582→  const value = params[key];
583→  return typeof value === "string" ? value : undefined;
584→}
585→
586→function readNumberParam(params: QueryParams, key: string): number | undefined {
587→  const value = params[key];
588→  return typeof value === "number" ? value : undefined;
589→}
590→
591→function isQueryResource(value: string): value is QueryResource {
592→  return (QUERY_RESOURCES as readonly string[]).includes(value);
593→}
594→
595→function toQueryResource(value: string): QueryResource {
596→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
597→  return value;
598→}
599→
600→function isMutationName(value: string): value is MutationName {
601→  return (MUTATION_NAMES as readonly string[]).includes(value);
602→}
603→
604→function toMutationName(value: string): MutationName {
605→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
606→  return value;
607→}
608→
609→function parseCommandFrame(msg: QueryParams): CommandFrameInput {
610→  return {
611→    id: requireString(msg.id, "id"),
612→    command: requireString(msg.command, "command"),
613→    params: getParams(msg.params),
614→  };
615→}
616→
617→function isCommandName(value: string): value is CommandName {
618→  return (COMMAND_NAMES as readonly string[]).includes(value);
619→}
620→
621→function toCommandName(value: string): CommandName {
622→  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
623→  return value;
624→}
