  }

  // PR URL change → auto-derive in-review
  if (pr_url !== undefined) {
    db.prepare('UPDATE workspaces SET pr_url = ? WHERE id = ?').run(pr_url, id);
    if (pr_url) autoProgressStatus(id, 'in-review');
  }

  if (state) {
    db.prepare('UPDATE workspaces SET state = ? WHERE id = ?').run(state, id);

