      const ws = getWorkspaceRaw(db, id);
      if (ws?.status === 'done') {
        autoProgressStatus(id, 'in-progress', { force: true });
      }
    }
  }

  invalidate(['workspaces', 'sessions', 'stats']);
  return c.json(getWorkspaceRaw(db, id));
});
```

