  invalidate(["workspaces", "stats"]);
  return { success: true };
})
```

### 5. Frontend Status System

**`src/features/sidebar/lib/status.ts`** — Extend to include workflow status:

The existing `DisplayStatus` (`idle | working | error | unread`) represents **real-time agent activity**. The new `WorkspaceStatus` represents **workflow phase**. These are separate concerns rendered in different places:

- **Agent activity** → shown as dot/animation next to workspace name (existing)
- **Workflow status** → shown as icon/label in a new position (e.g., left of workspace name, or as a column in list view)

No changes needed to `getDisplayStatus()` — it stays focused on agent activity.

**New: status icon + color config:**
```typescript
export const WORKSPACE_STATUS_CONFIG: Record<WorkspaceStatus, { icon: string; color: string; label: string }> = {
  "backlog":     { icon: "circle",       color: "text-muted-foreground", label: "Backlog" },
  "in-progress": { icon: "circle-half",  color: "text-amber-500",       label: "In Progress" },
  "in-review":   { icon: "circle-dot",   color: "text-purple-500",      label: "In Review" },
  "done":        { icon: "circle-check", color: "text-green-500",       label: "Done" },
  "canceled":    { icon: "circle-x",     color: "text-muted-foreground", label: "Canceled" },
};
```

### 6. Frontend Mutation Hook

**`src/features/workspace/api/workspace.mutations.ts`** (or similar):
```typescript
export function useUpdateWorkspaceStatus() {
  const { sendMutation } = useSocket();
  return useMutation({
    mutationFn: ({ workspaceId, status }: { workspaceId: string; status: WorkspaceStatus }) =>
      sendMutation("updateWorkspaceStatus", { workspaceId, status }),
  });
}
```

### 7. Stats Query

**`backend/src/db/queries.ts`** — Extend `getStats()` to include status counts:
```sql
(SELECT COUNT(*) FROM workspaces WHERE status = 'backlog') as workspaces_backlog,
(SELECT COUNT(*) FROM workspaces WHERE status = 'in-progress') as workspaces_in_progress,
(SELECT COUNT(*) FROM workspaces WHERE status = 'in-review') as workspaces_in_review,
(SELECT COUNT(*) FROM workspaces WHERE status = 'done') as workspaces_done,
(SELECT COUNT(*) FROM workspaces WHERE status = 'canceled') as workspaces_canceled,
```

---

## Auto-Derive Implementation

Create a helper function used across all status transition points:

**`backend/src/services/workspace-status.service.ts`**:
```typescript
import { STICKY_STATUSES, type WorkspaceStatus } from "@shared/enums";
import { getDatabase } from "../lib/database";
import { getWorkspaceRaw } from "../db";
import { invalidate } from "./query-engine";

/**
 * Auto-progress a workspace's workflow status.
 * Respects sticky states (backlog, canceled) — won't auto-move them.
 * Archive events override even sticky states.
 */
export function autoProgressStatus(
  workspaceId: string,
  targetStatus: WorkspaceStatus,
  options: { force?: boolean } = {}
): void {
  const db = getDatabase();
  const ws = getWorkspaceRaw(db, workspaceId);
  if (!ws) return;

  const currentStatus = ws.status as WorkspaceStatus;

  // Sticky states resist auto-progression (unless forced, e.g. archive)
  if (!options.force && STICKY_STATUSES.has(currentStatus)) return;

  // Don't regress (in-review → in-progress would be wrong)
  const ORDER: WorkspaceStatus[] = ["backlog", "in-progress", "in-review", "done", "canceled"];
  const currentIdx = ORDER.indexOf(currentStatus);
  const targetIdx = ORDER.indexOf(targetStatus);
  if (!options.force && targetIdx <= currentIdx) return;

  db.prepare("UPDATE workspaces SET status = ? WHERE id = ?").run(targetStatus, workspaceId);
  invalidate(["workspaces", "stats"]);
}
```

**Call sites:**
1. `POST /workspaces` — default `'in-progress'` (DB default, no code needed)
2. Wherever `pr_url` is set — `autoProgressStatus(id, 'in-review')`
3. `PATCH /workspaces/:id` with `state='archived'` — `autoProgressStatus(id, 'done', { force: true })`
4. Future: PR merge webhook/check — `autoProgressStatus(id, 'done')`

---

## Migration Strategy

Since we use `initDatabase()` with `SCHEMA_SQL` (no migration system), the approach is:

1. Add `status TEXT NOT NULL DEFAULT 'in-progress'` to the CREATE TABLE in `SCHEMA_SQL`
2. Add `CREATE INDEX idx_workspaces_status` to `SCHEMA_SQL`
3. After the schema runs, add a one-time backfill query:
   ```sql
   -- Only runs if column was just added (all values are default 'in-progress')
   UPDATE workspaces SET status = 'done' WHERE state = 'archived' AND archive_commit IS NOT NULL AND status = 'in-progress';
   UPDATE workspaces SET status = 'in-review' WHERE pr_url IS NOT NULL AND state = 'ready' AND status = 'in-progress';
   ```

