  1→// backend/src/services/agent/client.ts
  2→// WebSocket client that connects to the agent-server (sidecar).
  3→//
  4→// Implements the JSON-RPC 2.0 handshake protocol:
  5→//   Backend → Agent: { method: "initialize", params: { version: "1.0", capabilities: {} } }
  6→//   Agent → Backend: { result: { version: "1.0", agents: [...], capabilities: {} } }
  7→//   Backend → Agent: { method: "initialized" } (notification)
  8→//
  9→// After handshake, exposes typed methods for turn lifecycle and listens for
 10→// canonical agent-event notifications.
 11→
 12→import { WebSocket } from "ws";
 13→import {
 14→  JSONRPCServer,
 15→  JSONRPCClient,
 16→  JSONRPCServerAndClient,
 17→  isJSONRPCRequest,
 18→  isJSONRPCRequests,
 19→  isJSONRPCResponse,
 20→  isJSONRPCResponses,
 21→} from "json-rpc-2.0";
 22→import {
 23→  AGENT_RPC_METHODS,
 24→  AGENT_EVENT_NAMES,
 25→  FRONTEND_RPC_METHODS,
 26→  AgentEventSchema,
 27→  InitializeResultSchema,
 28→  type InitializeResult,
 29→  type TurnStartRequest,
 30→  type TurnStartResponse,
 31→  type TurnCancelRequest,
 32→  type TurnRespondRequest,
 33→  type SessionResetRequest,
 34→  type SessionStopRequest,
 35→  type ProviderAuthRequest,
 36→  type ProviderInitWorkspaceRequest,
 37→  type ProviderContextUsageRequest,
 38→  type ProviderUpdateModeRequest,
 39→  type AgentEvent,
 40→  type AgentInfo,
 41→} from "../../../../shared/agent-events";
 42→
 43→// ============================================================================
 44→// Types
 45→// ============================================================================
 46→
 47→export type AgentEventHandler = (event: AgentEvent) => void;
 48→
 49→export interface AgentClientOptions {
 50→  /** ws://127.0.0.1:{port} — the agent-server URL */
 51→  url: string;
 52→  /** Called for every canonical agent-event notification received from the agent-server */
 53→  onEvent?: AgentEventHandler;
 54→  /** Called when the connection is established and handshake completes */
 55→  onConnected?: (agents: AgentInfo[]) => void;
 56→  /** Called when the connection drops */
 57→  onDisconnected?: () => void;
 58→  /** Called when the sidecar sends a frontend-facing RPC (browser, sim, diff, plan).
 59→   *  Must relay to the frontend and return the result. */
 60→  onFrontendRpc?: (requestId: string, sessionId: string, method: string, params: Record<string, unknown>) => Promise<unknown>;
 61→}
 62→
 63→// ============================================================================
 64→// Reconnect constants
 65→// ============================================================================
 66→
 67→const BASE_RECONNECT_DELAY_MS = 1_000;
 68→const MAX_RECONNECT_DELAY_MS = 30_000;
 69→const HANDSHAKE_TIMEOUT_MS = 10_000;
 70→const PROTOCOL_VERSION = "1.0";
 71→
 72→// ============================================================================
 73→// AgentClient
 74→// ============================================================================
 75→
 76→export class AgentClient {
 77→  private url: string;
 78→  private ws: WebSocket | null = null;
 79→  private peer: JSONRPCServerAndClient | null = null;
 80→  private onEvent: AgentEventHandler;
 81→  private onConnected?: (agents: AgentInfo[]) => void;
 82→  private onDisconnected?: () => void;
 83→  private onFrontendRpc: (requestId: string, sessionId: string, method: string, params: Record<string, unknown>) => Promise<unknown>;
 84→
 85→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 86→  private reconnectAttempt = 0;
 87→  private disposed = false;
 88→  private connected = false;
 89→
 90→  /** Agents discovered during the initialize handshake */
 91→  private agents: AgentInfo[] = [];
 92→
 93→  constructor(options: AgentClientOptions) {
 94→    this.url = options.url;
 95→    this.onEvent = options.onEvent ?? (() => {});
 96→    this.onConnected = options.onConnected;
 97→    this.onDisconnected = options.onDisconnected;
 98→    this.onFrontendRpc = options.onFrontendRpc ?? (() => Promise.reject(new Error("No frontend RPC handler registered")));
 99→  }
100→
101→  // ==========================================================================
102→  // Public API
103→  // ==========================================================================
104→
105→  /** Initiate connection to the agent-server. Auto-reconnects on drop. */
106→  connect(): void {
107→    if (this.disposed) return;
108→    if (this.ws && this.ws.readyState !== WebSocket.CLOSED) {
109→      return;
110→    }
111→    this.cancelReconnect();
112→    this.openConnection();
113→  }
114→
115→  /** Permanently disconnect and stop reconnecting. */
116→  disconnect(): void {
117→    this.disposed = true;
118→    this.cancelReconnect();
119→    this.closeConnection();
120→  }
121→
122→  /** Returns true if the handshake is complete and the connection is open. */
123→  isConnected(): boolean {
124→    return this.connected && this.ws?.readyState === WebSocket.OPEN;
125→  }
126→
127→  /** Returns the agents discovered during handshake. */
128→  getAgents(): ReadonlyArray<AgentInfo> {
129→    return this.agents;
130→  }
131→
132→  // ---- Turn lifecycle RPCs ----
133→
134→  async sendTurnStart(params: TurnStartRequest): Promise<TurnStartResponse> {
135→    return this.request(AGENT_RPC_METHODS.TURN_START, params) as Promise<TurnStartResponse>;
136→  }
137→
138→  async sendTurnCancel(params: TurnCancelRequest): Promise<void> {
139→    await this.request(AGENT_RPC_METHODS.TURN_CANCEL, params);
140→  }
141→
142→  async sendTurnRespond(params: TurnRespondRequest): Promise<void> {
143→    await this.request(AGENT_RPC_METHODS.TURN_RESPOND, params);
144→  }
145→
146→  // ---- Session lifecycle RPCs ----
147→
148→  async sendSessionReset(params: SessionResetRequest): Promise<void> {
149→    await this.request(AGENT_RPC_METHODS.SESSION_RESET, params);
150→  }
151→
152→  async sendSessionStop(params: SessionStopRequest): Promise<void> {
153→    await this.request(AGENT_RPC_METHODS.SESSION_STOP, params);
154→  }
155→
156→  // ---- Provider operations ----
157→
158→  async sendProviderAuth(params: ProviderAuthRequest): Promise<unknown> {
159→    return this.request(AGENT_RPC_METHODS.PROVIDER_AUTH, params);
160→  }
161→
162→  async sendProviderInitWorkspace(params: ProviderInitWorkspaceRequest): Promise<unknown> {
163→    return this.request(AGENT_RPC_METHODS.PROVIDER_INIT_WORKSPACE, params);
164→  }
165→
166→  async sendProviderContextUsage(params: ProviderContextUsageRequest): Promise<unknown> {
167→    return this.request(AGENT_RPC_METHODS.PROVIDER_CONTEXT_USAGE, params);
168→  }
169→
170→  async sendProviderUpdateMode(params: ProviderUpdateModeRequest): Promise<void> {
171→    this.notify(AGENT_RPC_METHODS.PROVIDER_UPDATE_MODE, params);
172→  }
173→
174→  // ---- Introspection ----
175→
176→  async listAgents(): Promise<AgentInfo[]> {
177→    const result = await this.request(AGENT_RPC_METHODS.AGENT_LIST, {});
178→    return (result as any)?.agents ?? [];
179→  }
180→
181→  // ==========================================================================
182→  // Connection lifecycle
183→  // ==========================================================================
184→
185→  private openConnection(): void {
186→    if (this.disposed) return;
187→
188→    console.log(`[AgentClient] Connecting to ${this.url}...`);
189→
190→    try {
191→      this.ws = new WebSocket(this.url);
192→    } catch (err) {
193→      console.error("[AgentClient] Failed to create WebSocket:", err);
194→      this.scheduleReconnect();
195→      return;
196→    }
197→
198→    this.ws.on("open", () => {
199→      console.log("[AgentClient] WebSocket connected, starting handshake...");
200→      this.reconnectAttempt = 0;
201→      this.setupPeer();
202→      void this.performHandshake();
203→    });
204→
205→    this.ws.on("message", (data: Buffer | string) => {
206→      const message = typeof data === "string" ? data : data.toString("utf8");
207→      this.handleMessage(message);
208→    });
209→
210→    this.ws.on("close", (code, reason) => {
211→      console.log(`[AgentClient] Connection closed: ${code} ${reason.toString()}`);
212→      this.teardownPeer();
213→      if (!this.disposed) this.scheduleReconnect();
214→    });
215→
216→    this.ws.on("error", (err) => {
217→      console.error("[AgentClient] WebSocket error:", err.message);
218→    });
219→  }
220→
221→  private closeConnection(): void {
222→    if (this.ws) {
223→      this.ws.removeAllListeners();
224→      if (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING) {
225→        this.ws.close(1000, "Client disconnecting");
226→      }
227→      this.ws = null;
228→    }
229→    this.teardownPeer();
230→  }
231→
232→  // ==========================================================================
233→  // JSON-RPC peer
234→  // ==========================================================================
235→
236→  private setupPeer(): void {
237→    const server = new JSONRPCServer({
238→      errorListener: (message, data) => {
239→        console.error("[AgentClient] RPC server error:", message, data);
240→      },
241→    });
242→
243→    const client = new JSONRPCClient((payload) => {
244→      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
245→        return Promise.reject(new Error("WebSocket is not open"));
246→      }
247→      try {
248→        this.ws.send(JSON.stringify(payload));
249→        return Promise.resolve();
250→      } catch (error) {
251→        return Promise.reject(error instanceof Error ? error : new Error(String(error)));
252→      }
253→    });
254→
255→    this.peer = new JSONRPCServerAndClient(server, client, {
256→      errorListener: (message, data) => {
257→        console.error("[AgentClient] RPC client error:", message, data);
258→      },
259→    });
260→
261→    // Register handlers for all agent-event notification methods.
262→    // The agent-server sends these as JSON-RPC notifications (no id).
263→    for (const eventName of Object.values(AGENT_EVENT_NAMES)) {
264→      this.peer.addMethod(eventName, async (params) => {
265→        this.dispatchEvent(eventName, params);
266→        return undefined; // notifications don't return a value
267→      });
268→    }
269→
270→    // Register handlers for frontend-facing RPC methods.
271→    // The sidecar's tools (browser, simulator, workspace) call these as
272→    // JSON-RPC requests through the tunnel. We relay them to the frontend
273→    // via tool-relay, which broadcasts a q:event tool:request and waits
274→    // for the frontend's q:tool_response.
275→    const frontendMethods = Object.values(FRONTEND_RPC_METHODS);
276→    for (const method of frontendMethods) {
277→      this.peer.addMethod(method, async (params: any) => {
278→        const requestId = crypto.randomUUID();
279→        const sessionId = params?.sessionId ?? "unknown";
280→        console.log(`[AgentClient] Frontend RPC: method=${method} requestId=${requestId} session=${sessionId}`);
281→        const result = await this.onFrontendRpc(requestId, sessionId, method, params ?? {});
282→        return result;
283→      });
284→    }
285→    console.log(`[AgentClient] Registered ${frontendMethods.length} frontend RPC methods`);
286→  }
287→
288→  private teardownPeer(): void {
289→    const wasConnected = this.connected;
290→    this.connected = false;
291→    if (this.peer) {
292→      this.peer.rejectAllPendingRequests("Connection closed");
293→      this.peer = null;
294→    }
295→    if (wasConnected) {
296→      this.onDisconnected?.();
297→    }
298→  }
299→
300→  private dispatchEvent(eventName: string, params: unknown): void {
301→    // Validate and normalize the event payload using the canonical schema.
302→    // If parsing fails, log and skip — don't crash the client.
303→    const parsed = AgentEventSchema.safeParse(params);
304→    if (!parsed.success) {
305→      console.error(`[AgentClient] Invalid event payload for "${eventName}":`, parsed.error.message);
306→      return;
307→    }
308→    try {
309→      this.onEvent(parsed.data);
310→    } catch (err) {
311→      console.error(`[AgentClient] Event handler threw for "${eventName}":`, err);
312→    }
313→  }
314→
315→  // ==========================================================================
316→  // Handshake
317→  // ==========================================================================
318→
319→  private async performHandshake(): Promise<void> {
320→    if (!this.peer) return;
321→
322→    try {
323→      const rawResult = await this.withTimeout(
324→        this.peer.request(AGENT_RPC_METHODS.INITIALIZE, {
325→          version: PROTOCOL_VERSION,
326→          capabilities: {},
327→        }),
328→        HANDSHAKE_TIMEOUT_MS,
329→        "initialize"
330→      );
331→
332→      const parsed = InitializeResultSchema.safeParse(rawResult);
333→      if (!parsed.success) {
334→        throw new Error(`Invalid initialize response: ${parsed.error.message}`);
335→      }
336→      const result: InitializeResult = parsed.data;
337→
338→      this.agents = result.agents;
339→      console.log(
340→        `[AgentClient] Handshake complete: version=${result.version} agents=[${this.agents.map((a) => a.type).join(", ")}]`
341→      );
342→
343→      // Send "initialized" notification (fire-and-forget)
344→      this.peer.notify(AGENT_RPC_METHODS.INITIALIZED, {}, undefined);
345→
346→      this.connected = true;
347→      this.onConnected?.(this.agents);
348→    } catch (err) {
349→      console.error("[AgentClient] Handshake failed:", err);
350→      // Close and reconnect
351→      this.closeConnection();
352→      if (!this.disposed) this.scheduleReconnect();
353→    }
354→  }
355→
356→  // ==========================================================================
357→  // Message dispatch
358→  // ==========================================================================
359→
360→  private handleMessage(message: string): void {
361→    if (!this.peer) return;
362→
363→    let payload: unknown;
364→    try {
365→      payload = JSON.parse(message);
366→    } catch {
367→      console.error("[AgentClient] Failed to parse JSON:", message.slice(0, 200));
368→      return;
369→    }
370→
371→    if (!isJsonRpcPayload(payload)) {
372→      console.error("[AgentClient] Received non-JSON-RPC payload");
373→      return;
374→    }
375→
376→    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
377→      console.error("[AgentClient] Failed to handle message:", e);
378→    });
379→  }
380→
381→  // ==========================================================================
382→  // Outbound helpers
383→  // ==========================================================================
384→
385→  private request(method: string, params: unknown): Promise<unknown> {
386→    if (!this.peer || !this.connected) {
387→      return Promise.reject(new Error(`AgentClient is not connected (method=${method})`));
388→    }
389→    return Promise.resolve(this.peer.request(method, params, undefined));
390→  }
391→
392→  private notify(method: string, params: unknown): void {
393→    if (!this.peer || !this.connected) {
394→      console.error(`[AgentClient] Cannot send notification "${method}" — not connected`);
395→      return;
396→    }
397→    this.peer.notify(method, params, undefined);
398→  }
399→
400→  // ==========================================================================
401→  // Reconnect
402→  // ==========================================================================
403→
404→  private scheduleReconnect(): void {
405→    if (this.reconnectTimer || this.disposed) return;
406→    const delay = Math.min(
407→      BASE_RECONNECT_DELAY_MS * 2 ** this.reconnectAttempt,
408→      MAX_RECONNECT_DELAY_MS
409→    );
410→    this.reconnectAttempt++;
411→    console.log(`[AgentClient] Reconnecting in ${delay}ms (attempt ${this.reconnectAttempt})...`);
412→    this.reconnectTimer = setTimeout(() => {
413→      this.reconnectTimer = null;
414→      this.openConnection();
415→    }, delay);
416→  }
417→
418→  private cancelReconnect(): void {
419→    if (this.reconnectTimer) {
420→      clearTimeout(this.reconnectTimer);
421→      this.reconnectTimer = null;
422→    }
423→  }
424→
425→  // ==========================================================================
426→  // Utilities
427→  // ==========================================================================
428→
429→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
430→    let timerId: ReturnType<typeof setTimeout> | undefined;
431→    const timeout = new Promise<never>((_, reject) => {
432→      timerId = setTimeout(() => {
433→        reject(new Error(`[AgentClient] ${label} timed out after ${ms}ms`));
434→      }, ms);
435→    });
436→    return Promise.race([promise, timeout]).finally(() => {
437→      if (timerId !== undefined) clearTimeout(timerId);
438→    });
439→  }
440→}
441→
442→// ============================================================================
443→// JSON-RPC payload type guard
444→// ============================================================================
445→
446→function isJsonRpcPayload(payload: unknown): boolean {
447→  return (
448→    isJSONRPCRequest(payload) ||
449→    isJSONRPCRequests(payload) ||
450→    isJSONRPCResponse(payload) ||
451→    isJSONRPCResponses(payload)
452→  );
453→}
