  1→// backend/src/services/agent/commands.ts
  2→// Business logic for q:command dispatch.
  3→//
  4→// Each command handler is a focused function that:
  5→//   1. Validates and extracts typed params
  6→//   2. Performs DB writes
  7→//   3. Triggers subscription invalidation
  8→//   4. Forwards to agent-server when needed
  9→//
 10→// The query engine (protocol layer) delegates here — it should never
 11→// contain business logic directly.
 12→
 13→import { match } from "ts-pattern";
 14→import { getDatabase } from "../../lib/database";
 15→import { getSessionRaw } from "../../db";
 16→import { writeUserMessage } from "../message-writer";
 17→import { persistSessionError } from "./persistence";
 18→import { invalidate } from "../query-engine";
 19→import * as agentService from "./service";
 20→import type { CommandName } from "../../../../shared/types/query-protocol";
 21→
 22→// ---- Types ----
 23→
 24→type QueryParams = Record<string, unknown>;
 25→
 26→interface CommandResult {
 27→  commandId?: string;
 28→}
 29→
 30→// ---- Command Dispatch ----
 31→
 32→export function runCommand(command: CommandName, params: QueryParams): CommandResult {
 33→  return match(command)
 34→    .with("sendMessage", () => handleSendMessage(params))
 35→    .with("stopSession", () => handleStopSession(params))
 36→    .exhaustive();
 37→}
 38→
 39→// ---- sendMessage ----
 40→
 41→function handleSendMessage(params: QueryParams): CommandResult {
 42→  const sessionId = readString(params, "sessionId");
 43→  const content = readString(params, "content");
 44→  const model = readString(params, "model");
 45→  if (!sessionId || !content) {
 46→    throw new Error("sendMessage requires sessionId and content");
 47→  }
 48→
 49→  // 1. Persist the user message
 50→  const result = writeUserMessage(sessionId, content, model);
 51→  if (!result.success) throw new Error(result.error);
 52→  invalidate(["workspaces", "sessions", "session", "messages", "stats"], { sessionIds: [sessionId] });
 53→
 54→  // 2. Forward to agent-server (fire-and-forget — ACK already sent)
 55→  const agentType = readString(params, "agentType") || "claude";
 56→
 57→  // Look up the existing agent_session_id so the SDK resumes the same
 58→  // conversation rather than starting a new one.
 59→  const db = getDatabase();
 60→  const session = getSessionRaw(db, sessionId);
 61→  const existingAgentSessionId = session?.agent_session_id ?? null;
 62→
 63→  if (agentService.isConnected()) {
 64→    agentService.forwardTurn({
 65→      sessionId,
 66→      agentType,
 67→      prompt: content,
 68→      options: buildTurnOptions(params, model, existingAgentSessionId),
 69→    }).then((response) => {
 70→      if (!response.accepted) {
 71→        handleAgentRejection(sessionId, agentType, response.reason);
 72→      }
 73→    }).catch((err) => {
 74→      handleAgentError(sessionId, agentType, err);
 75→    });
 76→  }
 77→
 78→  return { commandId: result.messageId };
 79→}
 80→
 81→// ---- stopSession ----
 82→
 83→function handleStopSession(params: QueryParams): CommandResult {
 84→  const sessionId = readString(params, "sessionId");
 85→  if (!sessionId) throw new Error("stopSession requires sessionId");
 86→
 87→  if (agentService.isConnected()) {
 88→    agentService.stopSession({ sessionId }).catch((err) => {
 89→      console.error("[CommandHandler] Failed to cancel on agent-server:", err);
 90→    });
 91→  }
 92→
 93→  const db = getDatabase();
 94→  const session = getSessionRaw(db, sessionId);
 95→  if (!session) throw new Error("Session not found");
 96→
 97→  db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(sessionId);
 98→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
 99→  return {};
100→}
101→
102→// ---- Helpers ----
103→
104→function buildTurnOptions(
105→  params: QueryParams,
106→  model: string | undefined,
107→  resume: string | null,
108→): Record<string, unknown> {
109→  return {
110→    cwd: readString(params, "cwd") || "",
111→    model,
112→    maxThinkingTokens: params.maxThinkingTokens as number | undefined,
113→    maxTurns: params.maxTurns as number | undefined,
114→    turnId: readString(params, "turnId"),
115→    permissionMode: readString(params, "permissionMode"),
116→    providerEnvVars: readString(params, "providerEnvVars"),
117→    ghToken: readString(params, "ghToken"),
118→    opendevsEnv: params.opendevsEnv as Record<string, string> | undefined,
119→    additionalDirectories: params.additionalDirectories as string[] | undefined,
120→    chromeEnabled: params.chromeEnabled as boolean | undefined,
121→    strictDataPrivacy: params.strictDataPrivacy as boolean | undefined,
122→    shouldResetGenerator: params.shouldResetGenerator as boolean | undefined,
123→    resume: resume || readString(params, "resume"),
124→    resumeSessionAt: readString(params, "resumeSessionAt"),
125→  };
126→}
127→
128→function handleAgentRejection(sessionId: string, agentType: string, reason?: string): void {
129→  const msg = reason || "Agent rejected the message";
130→  console.error(`[CommandHandler] Agent rejected sendMessage for session=${sessionId}: ${msg}`);
131→  persistSessionError({
132→    type: "session.error",
133→    sessionId,
134→    agentType: agentType as "claude",
135→    error: msg,
136→    category: "internal",
137→  });
138→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
139→}
140→
141→function handleAgentError(sessionId: string, agentType: string, err: unknown): void {
142→  const errorMsg = err instanceof Error ? err.message : String(err);
143→  console.error("[CommandHandler] Failed to forward to agent-server:", errorMsg);
144→  persistSessionError({
145→    type: "session.error",
146→    sessionId,
147→    agentType: agentType as "claude",
148→    error: `Agent server communication failed: ${errorMsg}`,
149→    category: "internal",
150→  });
151→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
152→}
153→
154→function readString(params: QueryParams, key: string): string | undefined {
155→  const value = params[key];
156→  return typeof value === "string" ? value : undefined;
157→}
158→

  1→// backend/src/services/agent/event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent → backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Created via createAgentEventHandler() — a factory that injects the
  9→// respondToAgent dependency, breaking the circular import with service.ts.
 10→
 11→import { match } from "ts-pattern";
 12→import type { AgentEvent } from "../../../../shared/agent-events";
 13→import type { QueryResource } from "../../../../shared/types/query-protocol";
 14→import { invalidate } from "../query-engine";
 15→import { relay } from "./tool-relay";
 16→import {
 17→  persistAssistantMessage,
 18→  persistToolResultMessage,
 19→  persistMessageResult,
 20→  persistMessageCancelled,
 21→  persistSessionStarted,
 22→  persistSessionIdle,
 23→  persistSessionError,
 24→  persistSessionCancelled,
 25→  persistAgentSessionId,
 26→  type WriteResult,
 27→} from "./persistence";
 28→
 29→// ---- Types ----
 30→
 31→type RespondToAgentFn = (params: {
 32→  sessionId: string;
 33→  requestId: string;
 34→  result: unknown;
 35→}) => Promise<void>;
 36→
 37→export type AgentEventHandler = (event: AgentEvent) => void;
 38→
 39→// ---- Resource groups for invalidation ----
 40→
 41→const SESSION_RESOURCES: QueryResource[] = ["workspaces", "sessions", "session", "stats"];
 42→const MESSAGE_RESOURCES: QueryResource[] = ["messages", "session"];
 43→
 44→// ---- Helpers ----
 45→
 46→/** Persist an event and invalidate subscriptions if the write succeeded. */
 47→function persistAndInvalidate(
 48→  result: WriteResult<unknown>,
 49→  resources: QueryResource[],
 50→  sessionId: string,
 51→): void {
 52→  if (result.ok) {
 53→    invalidate(resources, { sessionIds: [sessionId] });
 54→  }
 55→}
 56→
 57→// ---- Factory ----
 58→
 59→/**
 60→ * Create an agent event handler with injected dependencies.
 61→ *
 62→ * The respondToAgent function is injected to break the circular dependency
 63→ * between this module and service.ts. The composition root (service.ts)
 64→ * provides the concrete implementation: client.sendTurnRespond().
 65→ */
 66→export function createAgentEventHandler(deps: {
 67→  respondToAgent: RespondToAgentFn;
 68→}): AgentEventHandler {
 69→  const { respondToAgent } = deps;
 70→
 71→  return function handleAgentEvent(event: AgentEvent): void {
 72→    match(event)
 73→      // ── Session lifecycle ─────────────────────────────────────────────
 74→      .with({ type: "session.started" }, (e) => {
 75→        console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 76→        persistAndInvalidate(persistSessionStarted(e), SESSION_RESOURCES, e.sessionId);
 77→      })
 78→      .with({ type: "session.idle" }, (e) => {
 79→        console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 80→        persistAndInvalidate(persistSessionIdle(e), SESSION_RESOURCES, e.sessionId);
 81→      })
 82→      .with({ type: "session.error" }, (e) => {
 83→        console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 84→        persistAndInvalidate(persistSessionError(e), SESSION_RESOURCES, e.sessionId);
 85→      })
 86→      .with({ type: "session.cancelled" }, (e) => {
 87→        console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 88→        persistAndInvalidate(persistSessionCancelled(e), SESSION_RESOURCES, e.sessionId);
 89→      })
 90→
 91→      // ── Messages ──────────────────────────────────────────────────────
 92→      .with({ type: "message.assistant" }, (e) => {
 93→        console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
 94→        persistAndInvalidate(persistAssistantMessage(e), MESSAGE_RESOURCES, e.sessionId);
 95→      })
 96→      .with({ type: "message.tool_result" }, (e) => {
 97→        console.log(`[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`);
 98→        persistAndInvalidate(persistToolResultMessage(e), MESSAGE_RESOURCES, e.sessionId);
 99→      })
100→      .with({ type: "message.result" }, (e) => {
101→        console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
102→        persistMessageResult(e);
103→      })
104→      .with({ type: "message.cancelled" }, (e) => {
105→        console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
106→        persistAndInvalidate(
107→          persistMessageCancelled(e),
108→          ["messages", "sessions", "session", "stats"],
109→          e.sessionId,
110→        );
111→      })
112→
113→      // ── Interaction requests ──────────────────────────────────────────
114→      .with({ type: "request.opened" }, (e) => {
115→        console.log(`[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`);
116→      })
117→      .with({ type: "request.resolved" }, (e) => {
118→        console.log(`[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`);
119→      })
120→
121→      // ── Tool relay ────────────────────────────────────────────────────
122→      .with({ type: "tool.request" }, (e) => {
123→        console.log(`[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`);
124→        void relayToolRequest(e, respondToAgent);
125→      })
126→
127→      // ── Metadata ──────────────────────────────────────────────────────
128→      .with({ type: "agent.session_id" }, (e) => {
129→        console.log(`[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`);
130→        persistAndInvalidate(persistAgentSessionId(e), SESSION_RESOURCES, e.sessionId);
131→      })
132→
133→      .exhaustive();
134→  };
135→}
136→
137→// ---- Tool relay internal ----
138→
139→async function relayToolRequest(
140→  event: AgentEvent & { type: "tool.request" },
141→  respondToAgent: RespondToAgentFn,
142→): Promise<void> {
143→  const { sessionId, requestId, method } = event;
144→
145→  try {
146→    const result = await relay(event);
147→    await respondToAgent({ sessionId, requestId, result });
148→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
149→  } catch (err) {
150→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
151→    try {
152→      await respondToAgent({
153→        sessionId,
154→        requestId,
155→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
156→      });
157→    } catch (respondErr) {
158→      console.error(`[AgentEvent] Failed to send error response to agent: requestId=${requestId}`, respondErr);
159→    }
160→  }
161→}
