 75→// ============================================================================
 76→// Timeout defaults (milliseconds)
 77→// ============================================================================
 78→
 79→/** Timeout for user-facing requests that require human interaction.
 80→ *  2 minutes allows users time to read multi-option questions and deliberate.
 81→ *  There is no UI countdown, so this must be generous. */
 82→const USER_FACING_TIMEOUT_MS = 120_000;
 83→
 84→/** Timeout for data-fetching requests that should resolve quickly */
 85→const DATA_QUERY_TIMEOUT_MS = 10_000;
 86→
 87→/** Timeout for browser snapshot — the accessibility tree builder on heavy
 88→ *  pages can take up to 15s (evalWithResult timeout), plus IPC overhead. */
 89→const BROWSER_SNAPSHOT_TIMEOUT_MS = 20_000;
 90→
 91→/** Timeout for browser navigate — allows extra time for auto-creating a tab,
 92→ *  waiting for the webview to initialize, loading the page, and taking a snapshot. */
 93→const BROWSER_NAVIGATE_TIMEOUT_MS = 30_000;
 94→
 95→/** Timeout for browser navigate-back — page load (15s) + snapshot (12s) + buffer. */
 96→const BROWSER_NAVIGATE_BACK_TIMEOUT_MS = 30_000;
 97→
 98→/** Timeout for BrowserWaitFor — polls for up to 30s inside the webview,
 99→ *  plus 5s buffer for eval overhead and title-channel round-trip. */
100→const BROWSER_WAIT_FOR_TIMEOUT_MS = 35_000;
101→
102→/** Timeout for BrowserEvaluate — user code can run expensive operations,
103→ *  frontend allows 15s for eval, plus IPC overhead. */
104→const BROWSER_EVALUATE_TIMEOUT_MS = 20_000;
105→
106→/** Timeout for BrowserScreenshot — native WKWebView.takeSnapshot() has a
107→ *  10s internal timeout, plus 5s buffer for IPC and base64 encoding. */
108→const BROWSER_SCREENSHOT_TIMEOUT_MS = 15_000;
109→
110→/** Timeout for browser interactions (click, type, hover, etc.) that include
111→ *  visual effects + eval. Visual cursor animation up to 3s + eval up to 8s. */
112→const BROWSER_INTERACTION_TIMEOUT_MS = 15_000;
113→
114→/** Timeout for simulator screenshot — Rust ObjC bridge capture + JPEG
115→ *  encoding + base64 transfer. Typically <2s but allow headroom. */
116→const SIMULATOR_SCREENSHOT_TIMEOUT_MS = 10_000;
117→
118→/** Timeout for simulator interactions (tap, swipe, type, key press) — HID
119→ *  injection through the ObjC bridge is fast but include IPC buffer. */
120→const SIMULATOR_INTERACTION_TIMEOUT_MS = 10_000;
121→
122→/** Timeout for simulator boot — booting a simulator and starting the MJPEG
123→ *  stream + ObjC bridge can take 15-20s on cold boot. */
124→const SIMULATOR_BOOT_TIMEOUT_MS = 30_000;
125→
126→/** Timeout for build-and-run — xcodebuild can take minutes for large projects.
127→ *  10 minutes matches the existing builder.ts timeout. */
128→const SIMULATOR_BUILD_TIMEOUT_MS = 600_000;
