139→  attachTunnel(tunnel: RpcConnection): void {
140→    this.tunnels.add(tunnel);
141→    console.log(`[EventBroadcaster] Tunnel attached (${this.tunnels.size} active)`);
142→  }
143→
144→  /**
145→   * Detach a specific tunnel. If tunnel is provided, removes only that one.
146→   * If no tunnel is provided, clears all tunnels.
147→   */
148→  detachTunnel(tunnel?: RpcConnection): void {
149→    if (tunnel) {
150→      this.tunnels.delete(tunnel);
151→      console.log(`[EventBroadcaster] Tunnel detached (${this.tunnels.size} remaining)`);
152→    } else {
153→      this.tunnels.clear();
154→      console.log("[EventBroadcaster] All tunnels cleared");
155→    }
156→  }
