545→  }
546→  requestSimStart(r: SimStartRequest) {
547→    return this.rpc<SimStartResponse>(FRONTEND_RPC_METHODS.SIM_START, r, SIMULATOR_BOOT_TIMEOUT_MS);
548→  }
549→
550→  // ==========================================================================
551→  // Internal helpers
552→  // ==========================================================================
553→
554→  /** Generic typed RPC: send a request to the frontend with a timeout. */
555→  private async rpc<TRes>(method: string, params: unknown, timeoutMs: number): Promise<TRes> {
556→    return this.withTimeout<TRes>(
557→      this.requireTunnel().request(method, params) as Promise<TRes>,
558→      timeoutMs,
559→      method
560→    );
561→  }
562→
563→  /** Returns the first available tunnel, or throws if none are connected. */
564→  private requireTunnel(): RpcConnection {
565→    const first = this.tunnels.values().next().value;
566→    if (!first) {
567→      throw new Error("EventBroadcaster tunnel not attached.");
568→    }
569→    return first;
570→  }
571→
572→  /**
573→   * Broadcast a notification to all connected tunnels.
574→   * Dead tunnels (those that throw on notify) are automatically removed.
575→   */
576→  private broadcastNotification(method: string, params: unknown, label: string): void {
577→    const t0 = Date.now();
578→    for (const tunnel of this.tunnels) {
579→      try {
580→        tunnel.notify(method, params);
581→      } catch (err) {
582→        console.error(`[EventBroadcaster] ${label} failed, removing dead tunnel:`, err);
583→        this.tunnels.delete(tunnel);
584→      }
585→    }
586→    const elapsed = Date.now() - t0;
587→    if (elapsed > 5) {
588→      console.log(
589→        `[TIMING][EventBroadcaster] ${label} broadcast took ${elapsed}ms (${this.tunnels.size} tunnels)`
590→      );
591→    }
592→  }
593→
594→  /**
595→   * Race a tunnel request against a timeout. Rejects with a descriptive
596→   * error if the frontend does not respond within `ms` milliseconds.
597→   */
598→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
599→    let timerId: ReturnType<typeof setTimeout> | undefined;
600→
601→    const timeout = new Promise<never>((_, reject) => {
602→      timerId = setTimeout(() => {
603→        reject(
604→          new Error(
605→            `[EventBroadcaster] ${label} timed out after ${ms}ms -- frontend did not respond`
606→          )
607→        );
608→      }, ms);
609→    });
610→
611→    return Promise.race([promise, timeout]).finally(() => {
612→      if (timerId !== undefined) clearTimeout(timerId);
613→    });
614→  }
615→}
616→
617→/** Singleton instance shared across the entire sidecar process */
618→export const EventBroadcaster = new EventBroadcasterClass();
