  1→// sidecar/agents/registry.ts
  2→// Agent handler interface, type definitions, and runtime registry.
  3→// Each agent type (claude, codex, etc.) implements AgentHandler and
  4→// registers itself in the registry during sidecar startup.
  5→
  6→import { getErrorMessage } from "../../shared/lib/errors";
  7→import type { AgentType } from "../protocol";
  8→import type { AgentCapabilities } from "../../shared/agent-events";
  9→import type { QueryOptions } from "../../shared/protocol";
 10→
 11→// Re-export so existing imports from registry still work
 12→export type { AgentCapabilities } from "../../shared/agent-events";
 13→export type { QueryOptions } from "../../shared/protocol";
 14→
 15→// ============================================================================
 16→// Optional method parameter types (provider-neutral names)
 17→// ============================================================================
 18→
 19→export interface AuthParams {
 20→  cwd: string;
 21→}
 22→
 23→export interface InitWorkspaceParams {
 24→  cwd: string;
 25→  ghToken?: string;
 26→  providerEnvVars?: string;
 27→}
 28→
 29→export interface ContextUsageParams {
 30→  id?: string;
 31→  options: { cwd: string; agentSessionId: string };
 32→}
 33→
 34→/**
 35→ * Common interface for all agent handlers.
 36→ *
 37→ * Core lifecycle methods (required):
 38→ * - initialize() — one-time setup (e.g., discover executable)
 39→ * - query() — process a user prompt
 40→ * - cancel() — cancel a running session
 41→ * - reset() — tear down generator for a session
 42→ *
 43→ * Optional provider-specific methods (guarded by capabilities):
 44→ * - auth() — check account auth info
 45→ * - initWorkspace() — get slash commands + MCP server status
 46→ * - getContextUsage() — fetch context window usage
 47→ * - updatePermissionMode() — hot-swap permission mode on active query
 48→ */
 49→export interface AgentHandler {
 50→  readonly agentType: AgentType;
 51→  readonly capabilities: AgentCapabilities;
 52→
 53→  initialize(): { success: boolean; error?: string };
 54→
 55→  query(sessionId: string, prompt: string, options: QueryOptions): Promise<void>;
 56→
 57→  cancel(sessionId: string): Promise<void>;
 58→
 59→  reset(sessionId: string): void;
 60→
 61→  // Optional provider-specific methods (guarded by capabilities)
 62→  auth?(params: AuthParams): Promise<any>;
 63→  initWorkspace?(params: InitWorkspaceParams): Promise<any>;
 64→  getContextUsage?(params: ContextUsageParams): Promise<any>;
 65→  updatePermissionMode?(sessionId: string, permissionMode: string): Promise<void>;
 66→}
 67→
 68→// ============================================================================
 69→// Agent Registry
 70→// ============================================================================
 71→
 72→const registry = new Map<AgentType, AgentHandler>();
 73→
 74→/**
 75→ * Registers an agent handler in the registry.
 76→ * Overwrites any existing handler for the same agentType.
 77→ */
 78→export function registerAgent(handler: AgentHandler): void {
 79→  registry.set(handler.agentType, handler);
 80→}
 81→
 82→/**
 83→ * Retrieves the agent handler for a given type.
 84→ * Returns undefined if no handler is registered for that type.
 85→ */
 86→export function getAgent(type: AgentType): AgentHandler | undefined {
 87→  return registry.get(type);
 88→}
 89→
 90→/**
 91→ * Initializes all registered agents and returns their results.
 92→ * Called once during sidecar startup after all agents are registered.
 93→ */
 94→export function initializeAllAgents(): Map<AgentType, { success: boolean; error?: string }> {
 95→  const results = new Map<AgentType, { success: boolean; error?: string }>();
 96→  for (const [type, handler] of registry) {
 97→    try {
 98→      const result = handler.initialize();
 99→      results.set(type, result);
100→    } catch (error) {
101→      results.set(type, {
102→        success: false,
103→        error: getErrorMessage(error),
104→      });
105→    }
106→  }
107→  return results;
108→}
109→
110→/**
111→ * Returns the list of registered agent type names.
112→ * Used by the health endpoint to report available agents.
113→ */
114→export function getRegisteredAgentTypes(): AgentType[] {
115→  return Array.from(registry.keys());
116→}
117→
118→/**
119→ * Clears the registry. Used in tests to reset state between runs.
120→ */
121→export function clearAgentRegistry(): void {
122→  registry.clear();
123→}
