 1→// sidecar/agents/session-store.ts
 2→// Generic typed session store — replaces the duplicated Map + get/set/delete
 3→// boilerplate in claude-session.ts and codex-session.ts.
 4→//
 5→// Each agent instantiates its own SessionStore<T> with its session state type.
 6→// The store provides a standard API plus an `owns()` guard for reference
 7→// identity checks used in the catch/finally paths of streaming loops.
 8→
 9→/**
10→ * Generic typed store for agent session state.
11→ *
12→ * Replaces the pattern of:
13→ *   const map = new Map<string, T>();
14→ *   export function get(id) { return map.get(id); }
15→ *   export function set(id, val) { map.set(id, val); }
16→ *   export function delete(id) { map.delete(id); }
17→ *
18→ * Each agent creates its own instance with its session state type:
19→ *   export const claudeSessions = new SessionStore<SessionState>();
20→ *   export const codexSessions = new SessionStore<CodexSessionState>();
21→ */
22→export class SessionStore<T> {
23→  private sessions = new Map<string, T>();
24→
25→  get(id: string): T | undefined {
26→    return this.sessions.get(id);
27→  }
28→
29→  set(id: string, state: T): void {
30→    this.sessions.set(id, state);
31→  }
32→
33→  delete(id: string): void {
34→    this.sessions.delete(id);
35→  }
36→
37→  has(id: string): boolean {
38→    return this.sessions.has(id);
39→  }
40→
41→  clear(): void {
42→    this.sessions.clear();
43→  }
44→
45→  /**
46→   * Check if the session reference matches (for ownership guards).
47→   *
48→   * Returns true when it's safe for the caller to mutate/clean up the session:
49→   * - No session exists for this id (nothing to clobber)
50→   * - The stored session is the same reference as `ref` (caller owns it)
51→   *
52→   * Returns false when a rapid re-query has replaced the session with a
53→   * different object — the caller's finally/catch block must NOT touch it.
54→   */
55→  owns(id: string, ref: T): boolean {
56→    if (!this.sessions.has(id)) return true;
57→    return this.sessions.get(id) === ref;
58→  }
59→}
