381→
382→// ---- Query Dispatch ----
383→
384→function runQuery(resource: QueryResource, params: QueryParams): unknown {
385→  const db = getDatabase();
386→
387→  return match(resource)
388→    .with("workspaces", () => {
389→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
390→      const state = readStringParam(params, "state") ?? "ready,initializing";
391→      const workspaces = getWorkspacesByRepo(db, state);
392→
393→      const grouped: Record<string, { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }> = {};
394→      workspaces.forEach(workspace => {
395→        const repoId = workspace.repository_id || "unknown";
396→        if (!grouped[repoId]) {
397→          grouped[repoId] = {
398→            repo_id: repoId,
399→            repo_name: workspace.repo_name || "Unknown",
400→            sort_order: workspace.repo_sort_order ?? 999,
401→            workspaces: [],
402→          };
403→        }
404→        grouped[repoId].workspaces.push({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
405→      });
406→
407→      // Backfill repos that have no matching workspaces (e.g. all archived)
408→      const allRepos = getAllRepositorySummaries(db);
409→      for (const repo of allRepos) {
410→        if (!grouped[repo.id]) {
411→          grouped[repo.id] = {
412→            repo_id: repo.id,
413→            repo_name: repo.name,
414→            sort_order: repo.sort_order ?? 999,
415→            workspaces: [],
416→          };
417→        }
418→      }
419→
420→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
421→    })
422→    .with("stats", () => getStats(db))
423→    .with("sessions", () => {
424→      const workspaceId = readStringParam(params, "workspaceId");
425→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
426→      return getSessionsByWorkspaceId(db, workspaceId);
427→    })
428→    .with("session", () => {
429→      const sessionId = readStringParam(params, "sessionId");
430→      if (!sessionId) throw new Error("session requires sessionId param");
431→      return getSessionById(db, sessionId);
432→    })
433→    .with("messages", () => {
434→      const sessionId = readStringParam(params, "sessionId");
435→      if (!sessionId) throw new Error("messages requires sessionId param");
436→
437→      const rows = getMessages(db, sessionId, {
438→        limit: readNumberParam(params, "limit") ?? 50,
439→        before: readNumberParam(params, "before"),
440→        after: readNumberParam(params, "after"),
441→      });
442→
443→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
444→      const hasNewer = rows.length > 0
445→        ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq)
446→        : false;
447→
448→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
449→    })
450→    .exhaustive();
451→}
452→
453→// ---- Mutation Dispatch ----
454→
455→function runMutation(action: string, params: QueryParams): unknown {
456→  const typedAction = toMutationName(action);
457→
458→  return match(typedAction)
459→    .with("archiveWorkspace", () => {
460→      const db = getDatabase();
461→      const workspaceId = readStringParam(params, "workspaceId");
462→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
463→
464→      const workspace = getWorkspaceRaw(db, workspaceId);
465→      if (!workspace) throw new Error("Workspace not found");
466→
467→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
468→      invalidate(["workspaces", "stats"]);
469→      return { success: true };
470→    })
471→    .with("updateWorkspaceTitle", () => {
472→      const db = getDatabase();
473→      const workspaceId = readStringParam(params, "workspaceId");
474→      const title = readStringParam(params, "title");
475→      if (!workspaceId || title === undefined) {
476→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
477→      }
478→
479→      const workspace = getWorkspaceRaw(db, workspaceId);
480→      if (!workspace) throw new Error("Workspace not found");
481→
482→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
483→      invalidate(["workspaces"]);
484→      return { success: true };
485→    })
486→    .exhaustive();
487→}
488→
489→// ---- Message Delta Push ----
490→
491→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
492→  const sessionId = readStringParam(params, "sessionId");
493→  if (!sessionId) return;
494→
495→  const cursorKey = `${connectionId}:${subId}`;
496→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
497→
498→  try {
499→    const db = getDatabase();
500→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
501→
502→    if (newMessages.length === 0) return;
503→
504→    const maxSeq = newMessages[newMessages.length - 1].seq;
505→    messageCursors.set(cursorKey, maxSeq);
506→
507→    sendFrame(connectionId, {
508→      type: "q:delta",
509→      id: subId,
510→      upserted: newMessages,
511→      cursor: maxSeq,
512→    });
513→  } catch (err) {
514→    console.error(`[QueryEngine] Message delta push failed:`, err);
515→  }
516→}
