214→/**
215→ * Fetch paginated messages for a session.
216→ * Uses seq (per-session monotonic integer) as cursor — no collisions,
217→ * no NULLs, integer comparison. sent_at had 15K+ collisions in production.
218→ */
219→export function getMessages(
220→  db: Database.Database,
221→  sessionId: string,
222→  opts: { limit: number; before?: number; after?: number }
223→): MessageRow[] {
224→  if (opts.before) {
225→    // Load older: fetch N messages before seq, then re-sort ascending
226→    return db.prepare(`
227→      SELECT * FROM (
228→        SELECT * FROM messages
229→        WHERE session_id = ? AND seq < ?
230→        ORDER BY seq DESC
231→        LIMIT ?
232→      ) sub ORDER BY seq ASC
233→    `).all(sessionId, opts.before, opts.limit) as MessageRow[];
234→  }
235→
236→  if (opts.after) {
237→    // Load newer: fetch N messages after seq, already in ascending order
238→    return db.prepare(`
239→      SELECT * FROM messages
240→      WHERE session_id = ? AND seq > ?
241→      ORDER BY seq ASC
242→      LIMIT ?
243→    `).all(sessionId, opts.after, opts.limit) as MessageRow[];
244→  }
245→
246→  // Default: load latest N messages (DESC then re-wrap ASC)
247→  return db.prepare(`
248→    SELECT * FROM (
249→      SELECT * FROM messages
250→      WHERE session_id = ?
251→      ORDER BY seq DESC
252→      LIMIT ?
253→    ) sub ORDER BY seq ASC
254→  `).all(sessionId, opts.limit) as MessageRow[];
255→}
