  1→/**
  2→ * Sidebar Status Configuration System
  3→ *
  4→ * Centralized configuration for workspace/session statuses, priorities, and visual styling.
  5→ * Design philosophy: Make it easy to iterate on colors and priorities without touching component code.
  6→ *
  7→ * @see src/features/session/types.ts for SessionStatus type definition
  8→ */
  9→
 10→import type { Workspace } from "@/features/workspace/types";
 11→
 12→/**
 13→ * Display status extends SessionStatus with derived states.
 14→ * 'unread' is derived from needs_response / needs_plan_response session status.
 15→ */
 16→export type DisplayStatus = "idle" | "working" | "error" | "unread";
 17→
 18→/**
 19→ * Priority levels for sorting (higher = more urgent)
 20→ */
 21→export enum StatusPriority {
 22→  ERROR = 4, // Critical - something broke
 23→  UNREAD = 3, // Important - needs review / response
 24→  WORKING = 2, // Active - in progress
 25→  IDLE = 0, // Dormant - no activity
 26→}
 27→
 28→/**
 29→ * Visual configuration for each status
 30→ *
 31→ * Design System:
 32→ * - badge: Color for notification badges (collapsed sidebar)
 33→ * - border: Border/glow color for active states
 34→ * - text: Text color for status labels
 35→ * - bg: Background color for sections/cards
 36→ *
 37→ * Color Semantics:
 38→ * 🔴 Red (error) = Critical, blocking, needs immediate action
 39→ * 🟡 Amber (unread) = Important, needs attention when ready
 40→ * 🟢 Green (working) = Active, positive, making progress
 41→ * 🟣 Purple (compacting) = Transient, maintenance, ignore
 42→ * ⚪ Gray (idle) = Dormant, background, low priority
 43→ */
 44→export interface StatusConfig {
 45→  priority: StatusPriority;
 46→  label: string;
 47→  labelActive: string; // Present continuous form (e.g., "Working...")
 48→  badge: string; // Tailwind classes for badge
 49→  border: string; // Tailwind classes for border/glow
 50→  text: string; // Tailwind classes for text
 51→  bg: string; // Tailwind classes for background
 52→  pulse?: boolean; // Whether to animate/pulse
 53→}
 54→
 55→/**
 56→ * Status configuration map
 57→ *
 58→ * IMPORTANT: To change colors, edit this object (no component changes needed)
 59→ */
 60→export const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
 61→  error: {
 62→    priority: StatusPriority.ERROR,
 63→    label: "Error",
 64→    labelActive: "Error",
 65→    badge: "bg-destructive text-destructive-foreground",
 66→    border: "border-destructive/60",
 67→    text: "text-destructive",
 68→    bg: "bg-destructive/10",
 69→    pulse: true,
 70→  },
 71→  unread: {
 72→    priority: StatusPriority.UNREAD,
 73→    label: "Needs Response",
 74→    labelActive: "Awaiting Input",
 75→    badge: "bg-status-unread text-status-unread-fg",
 76→    border: "border-status-unread/60",
 77→    text: "text-status-unread",
 78→    bg: "bg-status-unread/10",
 79→    pulse: false,
 80→  },
 81→  working: {
 82→    priority: StatusPriority.WORKING,
 83→    label: "Working",
 84→    labelActive: "Working...",
 85→    badge: "bg-primary text-primary-foreground",
 86→    border: "border-primary/60",
 87→    text: "text-primary",
 88→    bg: "bg-primary/10",
 89→    pulse: true,
 90→  },
 91→  idle: {
 92→    priority: StatusPriority.IDLE,
 93→    label: "Idle",
 94→    labelActive: "Idle",
 95→    badge: "bg-muted text-muted-foreground",
 96→    border: "border-muted",
 97→    text: "text-muted-foreground",
 98→    bg: "bg-muted/30",
 99→    pulse: false,
100→  },
101→};
102→
103→/**
104→ * Derive display status from workspace data
105→ *
106→ * Priority logic:
107→ * 1. Error — session in error state
108→ * 2. Unread — agent needs user response (needs_response / needs_plan_response)
109→ * 3. Working — agent actively processing
110→ * 4. Idle — dormant
111→ *
112→ * @param workspace Workspace data with session info
113→ * @returns Derived display status for UI rendering
114→ */
115→export function getDisplayStatus(workspace: Workspace): DisplayStatus {
116→  const status = workspace.session_status;
117→
118→  if (status === "error") return "error";
119→  if (status === "needs_response" || status === "needs_plan_response") return "unread";
120→  if (status === "working") return "working";
121→  return "idle";
122→}
123→
124→/**
125→ * Check if workspace needs user attention.
126→ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
127→ */
128→export function getUnreadCount(workspace: Workspace): number {
129→  const status = workspace.session_status;
130→  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
131→}
132→
133→/**
134→ * Sort workspaces by status priority
135→ * Higher priority statuses appear first
136→ *
137→ * @param workspaces Array of workspaces to sort
138→ * @returns Sorted array (original array not mutated)
139→ */
140→export function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
141→  return [...workspaces].sort((a, b) => {
142→    const statusA = getDisplayStatus(a);
143→    const statusB = getDisplayStatus(b);
144→    const priorityA = STATUS_CONFIG[statusA].priority;
145→    const priorityB = STATUS_CONFIG[statusB].priority;
146→
147→    // Higher priority first
148→    if (priorityA !== priorityB) {
149→      return priorityB - priorityA;
150→    }
151→
152→    // Same priority: sort by latest activity (most recent first)
153→    const timeA = new Date(a.updated_at).getTime();
154→    const timeB = new Date(b.updated_at).getTime();
155→    return timeB - timeA;
156→  });
157→}
158→
159→/**
160→ * Group workspaces by display status
161→ * Used for rendering section headers in expanded sidebar
162→ *
163→ * @param workspaces Array of workspaces to group
164→ * @returns Object with status as keys, workspace arrays as values
165→ */
166→export function groupByStatus<T extends Workspace>(
167→  workspaces: T[]
168→): Partial<Record<DisplayStatus, T[]>> {
169→  const groups: Partial<Record<DisplayStatus, T[]>> = {};
170→
171→  workspaces.forEach((workspace) => {
172→    const status = getDisplayStatus(workspace);
173→    if (!groups[status]) {
174→      groups[status] = [];
175→    }
176→    groups[status]!.push(workspace);
177→  });
178→
179→  return groups;
180→}
181→
182→/**
183→ * Get aggregate status counts for a repository
184→ * Used for collapsed sidebar status indicators
185→ *
186→ * @param workspaces Workspaces in a repository
187→ * @returns Count of each status type
188→ */
189→export function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
190→  const counts: Record<DisplayStatus, number> = {
191→    error: 0,
192→    unread: 0,
193→    working: 0,
194→    idle: 0,
195→  };
196→
197→  workspaces.forEach((workspace) => {
198→    const status = getDisplayStatus(workspace);
199→    counts[status]++;
200→  });
201→
202→  return counts;
203→}
204→
205→/**
206→ * Get total unread count for a repository
207→ * Sums unread across all workspaces
208→ */
209→export function getRepoUnreadCount(workspaces: Workspace[]): number {
210→  return workspaces.reduce((sum, workspace) => {
211→    return sum + getUnreadCount(workspace);
212→  }, 0);
213→}
214→
215→/**
216→ * Get highest priority status for a repository
217→ * Used for collapsed sidebar badge color
218→ *
219→ * @param workspaces Workspaces in a repository
220→ * @returns The highest priority status present
221→ */
222→export function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
223→  let highestPriority = StatusPriority.IDLE;
224→  let highestStatus: DisplayStatus = "idle";
225→
226→  workspaces.forEach((workspace) => {
227→    const status = getDisplayStatus(workspace);
228→    const priority = STATUS_CONFIG[status].priority;
229→
230→    if (priority > highestPriority) {
231→      highestPriority = priority;
232→      highestStatus = status;
233→    }
234→  });
235→
236→  return highestStatus;
237→}
