  1→import React from "react";
  2→import { match } from "ts-pattern";
  3→import { Archive, Loader2 } from "lucide-react";
  4→import NumberFlow from "@number-flow/react";
  5→
  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration } from "@/shared/hooks";
  8→import { PixelGrid } from "@/features/session/ui/PixelGrid";
  9→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 10→import type { WorkspaceItemProps } from "../model/types";
 11→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 12→
 13→/**
 14→ * Whether this status shows an icon in the 20x20 slot.
 15→ * working → PixelGrid generating, unread → gold dot, error → red dot.
 16→ * Only idle shows no icon (26px padding).
 17→ */
 18→const hasStatusIcon = (status: string) =>
 19→  status === "working" || status === "unread" || status === "error";
 20→
 21→/**
 22→ * WorkspaceItem — Sidebar workspace row
 23→ *
 24→ * Layout:  [Left (flex-1)]  [Right]
 25→ *   Left:
 26→ *     Row 1: [Icon 20×20 | pad-left 26px] [branch name]
 27→ *     Row 2: [pad-left 26px] [directory · status]
 28→ *   Right:
 29→ *     [+additions -deletions]
 30→ *
 31→ * Icons: working → PixelGrid generating, error → red dot, unread → gold dot.
 32→ * Idle → no icon (26px indent).
 33→ *
 34→ * State: "initializing" → shimmer row with PixelGrid thinking + "Setting up..."
 35→ */
 36→export const WorkspaceItem = React.memo(function WorkspaceItem({
 37→  workspace,
 38→  isActive,
 39→  diffStats,
 40→  onClick,
 41→  onArchive,
 42→}: WorkspaceItemProps) {
 43→  const isInitializing = workspace.state === "initializing";
 44→
 45→  // Hooks must be called unconditionally (React rules of hooks)
 46→  const { duration } = useWorkingDuration({
 47→    status: workspace.session_status,
 48→    latestMessageSentAt: workspace.latest_message_sent_at,
 49→  });
 50→
 51→  // Initializing state: non-interactive row with loading animation
 52→  if (isInitializing) {
 53→    return (
 54→      <li className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 55→        <SidebarRow
 56→          variant="workspace"
 57→          isActive={false}
 58→          aria-label="Workspace setting up"
 59→          className="pointer-events-none"
 60→        >
 61→          <div className="flex min-w-0 flex-1 flex-col gap-0.5 animate-[shimmer_2s_ease-in-out_infinite]">
 62→            {/* Row 1: thinking icon + branch name (or placeholder) */}
 63→            <div className="flex min-w-0 items-center gap-1.5">
 64→              <SidebarRowIconSlot>
 65→                <PixelGrid variant="thinking" size={14} />
 66→              </SidebarRowIconSlot>
 67→              <span className="text-text-disabled truncate text-base font-normal">
 68→                {workspace.git_branch || "New workspace"}
 69→              </span>
 70→            </div>
 71→            {/* Row 2: directory · status */}
 72→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 73→              {workspace.slug && (
 74→                <>
 75→                  <span className="text-text-disabled truncate text-xs">
 76→                    {workspace.slug}
 77→                  </span>
 78→                  <span className="text-text-disabled text-xs">·</span>
 79→                </>
 80→              )}
 81→              <span className="text-text-muted shrink-0 text-xs">
 82→                {match(workspace.init_stage)
 83→                  .with("worktree", () => "Creating worktree...")
 84→                  .with("dependencies", () => "Installing dependencies...")
 85→                  .with("hooks", () => "Setting up environment...")
 86→                  .with("session", () => "Finalizing...")
 87→                  .otherwise(() => "Setting up...")}
 88→              </span>
 89→            </div>
 90→          </div>
 91→        </SidebarRow>
 92→      </li>
 93→    );
 94→  }
 95→
 96→  const formatTime = (timestamp: string) => {
 97→    const date = new Date(timestamp);
 98→    const now = new Date();
 99→    const diffMs = now.getTime() - date.getTime();
100→    const diffMins = Math.floor(diffMs / 60000);
101→    const diffHours = Math.floor(diffMins / 60);
102→    const diffDays = Math.floor(diffHours / 24);
103→    const diffMonths = Math.floor(diffDays / 30);
104→
105→    if (diffMins < 1) return "now";
106→    if (diffMins < 60) return `${diffMins}m ago`;
107→    if (diffHours < 24) return `${diffHours}h ago`;
108→    if (diffDays < 30) return `${diffDays}d ago`;
109→    return `${diffMonths}mo ago`;
110→  };
111→
112→  const displayStatus = getDisplayStatus(workspace);
113→  const statusConfig = STATUS_CONFIG[displayStatus];
114→  const showIcon = hasStatusIcon(displayStatus);
115→  // 20px icon + 6px gap = 26px indent for rows without an icon
116→  const rowIndent = "pl-[26px]";
117→
118→  const isSetupRunning = workspace.setup_status === "running";
119→  const isSetupFailed = workspace.setup_status === "failed";
120→
121→  const statusTextClass = isSetupFailed
122→    ? "text-accent-red-muted"
123→    : isSetupRunning
124→      ? "text-text-muted"
125→      : match(displayStatus)
126→          .with("working", () => "text-text-tertiary")
127→          .with("unread", () => "text-text-secondary")
128→          .with("error", () => "text-accent-red-muted")
129→          .otherwise(() => "text-text-disabled");
130→
131→  const getStatusText = (): string => {
132→    if (isSetupRunning) return "Installing...";
133→    if (isSetupFailed) return "Setup failed";
134→    if (workspace.state === "archived") return "Archived";
135→    if (!workspace.session_status) return formatTime(workspace.updated_at);
136→
137→    return match(displayStatus)
138→      .with("idle", () => formatTime(workspace.updated_at))
139→      .with("unread", () => "Needs response")
140→      .with("working", () =>
141→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
142→      )
143→      .with("error", () => STATUS_CONFIG.error.label)
144→      .otherwise(() => statusConfig.label);
145→  };
146→
147→  const statusText = getStatusText();
148→  const showStatusDot = Boolean(workspace.slug && statusText);
149→
150→  const additions = diffStats?.additions ?? 0;
151→  const deletions = diffStats?.deletions ?? 0;
152→  const hasChanges = additions > 0 || deletions > 0;
153→
154→  const handleArchive = (e: React.MouseEvent) => {
155→    e.stopPropagation();
156→    if (onArchive) {
157→      onArchive(workspace.id);
158→    }
159→  };
160→
161→  const isArchived = workspace.state === "archived";
162→  const canArchive = !isArchived && !!onArchive;
163→  const isActiveState =
164→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
165→
166→  return (
167→    <li>
168→      <SidebarRow
169→        variant="workspace"
170→        isActive={isActive}
171→        role="button"
172→        tabIndex={0}
173→        data-workspace-id={workspace.id}
174→        className="cursor-pointer"
175→        aria-current={isActive ? "page" : undefined}
176→        aria-label={`Workspace ${workspace.git_branch} on ${workspace.slug}`}
177→        onClick={() => onClick(workspace)}
178→        onKeyDown={(e) => {
179→          if (e.key === " ") e.preventDefault();
180→        }}
181→        onKeyUp={(e) => {
182→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
183→        }}
184→      >
185→        {/* Left: rows */}
186→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
187→          {/* Row 1: icon + branch name */}
188→          <div className={cn("flex min-w-0 items-center gap-1.5", !showIcon && rowIndent)}>
189→            {showIcon && (
190→              <SidebarRowIconSlot>
191→                {displayStatus === "working" ? (
192→                  <PixelGrid variant="generating" size={14} />
193→                ) : displayStatus === "error" ? (
194→                  <span className="bg-accent-red h-2 w-2 rounded-full" />
195→                ) : (
196→                  /* unread: gold dot */
197→                  <span className="bg-accent-gold h-2 w-2 rounded-full" />
198→                )}
199→              </SidebarRowIconSlot>
200→            )}
201→            <span
202→              className={cn(
203→                "truncate text-base",
204→                isActive
205→                  ? "text-text-primary font-medium"
206→                  : isActiveState
207→                    ? "text-text-primary font-normal"
208→                    : "text-text-tertiary font-normal"
209→              )}
210→            >
211→              {workspace.git_branch}
212→            </span>
213→          </div>
214→
215→          {/* Row 2: directory · status */}
216→          <div className={cn("flex min-w-0 items-center gap-1.5", rowIndent)}>
217→            <span
218→              className={cn(
219→                "truncate text-xs",
220→                isActiveState ? "text-text-tertiary" : "text-text-disabled"
221→              )}
222→            >
223→              {workspace.slug}
224→            </span>
225→            {showStatusDot && (
226→              <span
227→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
228→              >
229→                ·
230→              </span>
231→            )}
232→            {statusText && (
233→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
234→                {isSetupRunning && <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />}
235→                {statusText}
236→              </span>
237→            )}
238→          </div>
239→        </div>
240→
241→        {/* Right: diff stats */}
242→        {hasChanges ? (
243→          <div
244→            className={cn(
245→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
246→              canArchive && "group-hover/sidebar-row:opacity-0"
247→            )}
248→          >
249→            {additions > 0 && (
250→              <NumberFlow
251→                value={additions}
252→                prefix="+"
253→                className={isActive ? "text-accent-green" : "text-text-muted"}
254→              />
255→            )}
256→            {deletions > 0 && (
257→              <NumberFlow
258→                value={deletions}
259→                prefix="-"
260→                className={isActive ? "text-accent-red" : "text-text-muted"}
261→              />
262→            )}
263→          </div>
264→        ) : null}
265→
266→        {/* Archive button — hover reveal */}
267→        {canArchive ? (
268→          <button
269→            type="button"
270→            onClick={handleArchive}
271→            aria-label={`Archive workspace ${workspace.git_branch}`}
272→            title="Archive workspace"
273→            className={cn(
274→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
275→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
276→              "group-hover/sidebar-row:opacity-100"
277→            )}
278→          >
279→            <Archive className="h-3.5 w-3.5" />
280→          </button>
281→        ) : null}
282→      </SidebarRow>
283→    </li>
284→  );
285→});
