  1→/**
  2→ * useSessionActions Hook
  3→ *
  4→ * Centralizes all session action handlers (send, stop, compact, create PR).
  5→ * Extracted from SessionPanel to reduce component complexity.
  6→ *
  7→ * Message Flow (sidecar-owns-send):
  8→ * 1. User clicks send → useSendMessage routes through socket → sidecar
  9→ * 2. Sidecar atomically: saves user message + sets status=working + dispatches agent
 10→ * 3. Sidecar streams response → saves to DB → notifies backend
 11→ * 4. Backend pushes q:snapshot/q:delta to WS subscribers → React Query cache → UI updates
 12→ */
 13→
 14→import { useCallback } from "react";
 15→import { toast } from "sonner";
 16→import { useSendMessage, useStopSession } from "../api/session.queries";
 17→import { sendCommand, connect, isConnected } from "@/platform/ws";
 18→import { track } from "@/platform/analytics";
 19→import { type RuntimeAgentType } from "../lib/agentRuntime";
 20→import { COMPACT_CONVERSATION, createPRPrompt } from "../lib/sessionPrompts";
 21→
 22→interface UseSessionActionsProps {
 23→  sessionId: string;
 24→  workspaceId?: string;
 25→  workspacePath: string;
 26→  messageInput: string;
 27→  model?: string;
 28→  agentType?: RuntimeAgentType;
 29→  onMessageSent?: () => void;
 30→  targetBranch?: string;
 31→}
 32→
 33→interface UseSessionActionsReturn {
 34→  // Actions
 35→  sendMessage: (customContent?: string) => Promise<void>;
 36→  stopSession: () => Promise<void>;
 37→  compactConversation: () => Promise<void>;
 38→  createPR: () => Promise<void>;
 39→
 40→  // Status
 41→  sending: boolean;
 42→}
 43→
 44→export function useSessionActions({
 45→  sessionId,
 46→  workspaceId,
 47→  workspacePath,
 48→  messageInput,
 49→  model,
 50→  agentType = "claude",
 51→  onMessageSent,
 52→  targetBranch = "main",
 53→}: UseSessionActionsProps): UseSessionActionsReturn {
 54→  const sendMessageMutation = useSendMessage();
 55→  const stopSessionMutation = useStopSession();
 56→
 57→  const sendMessage = useCallback(
 58→    async (customContent?: string) => {
 59→      const content = customContent || messageInput.trim();
 60→      if (!content || sendMessageMutation.isPending) return;
 61→
 62→      try {
 63→        // Single atomic call: sidecar saves message + starts agent.
 64→        // Optimistic UI fires in onMutate, rollback fires in onError.
 65→        await sendMessageMutation.mutateAsync({
 66→          sessionId,
 67→          content,
 68→          model,
 69→          cwd: workspacePath,
 70→          agentType,
 71→        });
 72→      } catch (error) {
 73→        console.error("Failed to send message:", error);
 74→        // onError already rolled back optimistic update.
 75→        // No stopSession cleanup needed — sidecar didn't persist anything on failure.
 76→        const reason = error instanceof Error ? error.message : "Failed to send message";
 77→        toast.error(reason);
 78→        return;
 79→      }
 80→
 81→      try {
 82→        onMessageSent?.();
 83→      } catch (callbackError) {
 84→        console.error("[useSessionActions] onMessageSent callback failed:", callbackError);
 85→      }
 86→    },
 87→    [messageInput, model, sendMessageMutation, sessionId, workspacePath, agentType, onMessageSent]
 88→  );
 89→
 90→  const stopSession = useCallback(async () => {
 91→    try {
 92→      // Cancel the sidecar agent first so it stops consuming API tokens
 93→      try {
 94→        if (!isConnected()) await connect();
 95→        await sendCommand("stopSession", { sessionId });
 96→      } catch (cancelError) {
 97→        console.error("[useSessionActions] Cancel query failed:", cancelError);
 98→      }
 99→      // Then update DB status to idle
100→      await stopSessionMutation.mutateAsync(sessionId);
101→    } catch (error) {
102→      console.error("Failed to stop session:", error);
103→    }
104→  }, [stopSessionMutation, sessionId, agentType]);
105→
106→  const compactConversation = useCallback(() => {
107→    return sendMessage(COMPACT_CONVERSATION);
108→  }, [sendMessage]);
109→
110→  const createPR = useCallback(() => {
111→    if (workspaceId) {
112→      track("pr_create_requested", { workspace_id: workspaceId, target_branch: targetBranch });
113→    }
114→    return sendMessage(createPRPrompt(targetBranch));
115→  }, [sendMessage, workspaceId, targetBranch]);
116→
117→  return {
118→    sendMessage,
119→    stopSession,
120→    compactConversation,
121→    createPR,
122→    sending: sendMessageMutation.isPending,
123→  };
124→}
125→

  1→/**
  2→ * WebSocket Query Protocol Client
  3→ *
  4→ * Singleton client that connects to the backend's /ws endpoint and handles
  5→ * the q:* protocol for real-time data subscriptions. Used by the desktop
  6→ * frontend to receive data pushes instead of HTTP polling.
  7→ *
  8→ * Protocol:
  9→ *   Client sends: q:subscribe, q:unsubscribe
 10→ *   Server sends: q:snapshot, q:delta, q:error, ping
 11→ *   Client responds to ping with pong
 12→ *
 13→ * On reconnect, all active subscriptions are re-established automatically.
 14→ */
 15→
 16→import { match } from "ts-pattern";
 17→import { getBackendPort } from "@/shared/config/api.config";
 18→import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 19→
 20→// ---- Types ----
 21→
 22→type SnapshotCallback = (data: unknown) => void;
 23→type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 24→type EventCallback = (event: string, data: unknown) => void;
 25→
 26→interface PendingCommand {
 27→  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 28→  reject: (err: Error) => void;
 29→}
 30→
 31→interface Subscription {
 32→  id: string;
 33→  resource: QueryResource;
 34→  params?: Record<string, unknown>;
 35→  onSnapshot: SnapshotCallback;
 36→  onDelta?: DeltaCallback;
 37→}
 38→
 39→// ---- Reconnect Config ----
 40→
 41→const BACKOFF_BASE_MS = 500;
 42→const BACKOFF_MAX_MS = 8000;
 43→
 44→// ---- Singleton State ----
 45→
 46→let ws: WebSocket | null = null;
 47→let _connectionId: string | null = null;
 48→let connected = false;
 49→let connecting = false;
 50→let reconnectAttempt = 0;
 51→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 52→let subCounter = 0;
 53→
 54→/** Active subscriptions keyed by client-assigned ID. */
 55→const subscriptions = new Map<string, Subscription>();
 56→
 57→/** Pending commands waiting for q:command_ack. */
 58→const pendingCommands = new Map<string, PendingCommand>();
 59→
 60→/** Listeners for q:event broadcasts. */
 61→const eventListeners = new Set<EventCallback>();
 62→
 63→/** Listeners notified when connection state changes (connected/disconnected). */
 64→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 65→
 66→/** Counter for generating unique command frame IDs. */
 67→let commandCounter = 0;
 68→
 69→/** Resolvers waiting for the initial "connected" frame after open. */
 70→let connectResolve: (() => void) | null = null;
 71→let connectReject: ((err: Error) => void) | null = null;
 72→
 73→// ---- Public API ----
 74→
 75→/** Generate a unique subscription ID. */
 76→function nextSubId(): string {
 77→  return `sub_${++subCounter}`;
 78→}
 79→
 80→/**
 81→ * Connect to the backend WebSocket. Resolves once authenticated.
 82→ * No-op if already connected or connecting.
 83→ */
 84→export async function connect(): Promise<void> {
 85→  if (connected) return;
 86→  if (connecting) {
 87→    // Wait for the in-flight connection attempt
 88→    return new Promise<void>((resolve, reject) => {
 89→      const prevResolve = connectResolve;
 90→      const prevReject = connectReject;
 91→      connectResolve = () => {
 92→        prevResolve?.();
 93→        resolve();
 94→      };
 95→      connectReject = (err) => {
 96→        prevReject?.(err);
 97→        reject(err);
 98→      };
 99→    });
100→  }
101→
102→  connecting = true;
103→
104→  return new Promise<void>((resolve, reject) => {
105→    connectResolve = resolve;
106→    connectReject = reject;
107→    openSocket().catch((err) => {
108→      connecting = false;
109→      connectReject?.(err);
110→      connectResolve = null;
111→      connectReject = null;
112→    });
113→  });
114→}
115→
116→/**
117→ * Subscribe to a query resource. Returns an unsubscribe function.
118→ *
119→ * On subscription, the server sends an initial q:snapshot. Subsequent
120→ * invalidations push q:snapshot (full replace) or q:delta (incremental).
121→ */
122→export function subscribe(
123→  resource: QueryResource,
124→  params: Record<string, unknown> | undefined,
125→  onSnapshot: SnapshotCallback,
126→  onDelta?: DeltaCallback
127→): () => void {
128→  const id = nextSubId();
129→  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
130→  subscriptions.set(id, sub);
131→
132→  // If connected, send subscribe frame immediately
133→  if (connected && ws) {
134→    sendFrame({
135→      type: "q:subscribe",
136→      id,
137→      resource,
138→      ...(params ? { params } : {}),
139→    });
140→  }
141→
142→  // Return unsubscribe function
143→  return () => {
144→    subscriptions.delete(id);
145→    if (connected && ws) {
146→      sendFrame({ type: "q:unsubscribe", id });
147→    }
148→  };
149→}
150→
151→/** Check if the client is currently connected. */
152→export function isConnected(): boolean {
153→  return connected;
154→}
155→
156→/**
157→ * Send an async command via the q:command frame.
158→ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
159→ * Returns a promise that resolves when the server sends q:command_ack.
160→ */
161→export function sendCommand(
162→  command: CommandName,
163→  params: Record<string, unknown>
164→): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
165→  const id = `cmd_${++commandCounter}`;
166→
167→  return new Promise((resolve, reject) => {
168→    pendingCommands.set(id, { resolve, reject });
169→
170→    const sent = sendFrame({
171→      type: "q:command",
172→      id,
173→      command,
174→      params,
175→    });
176→
177→    // Reject immediately if the frame couldn't be sent (WS disconnected)
178→    if (!sent) {
179→      pendingCommands.delete(id);
180→      reject(new Error("WebSocket not connected"));
181→      return;
182→    }
183→
184→    // Timeout after 30s to prevent leaked promises
185→    setTimeout(() => {
186→      if (pendingCommands.has(id)) {
187→        pendingCommands.delete(id);
188→        reject(new Error(`Command ${command} timed out`));
189→      }
190→    }, 30_000);
191→  });
192→}
193→
194→/**
195→ * Register a callback for q:event broadcasts.
196→ * Returns an unregister function.
197→ */
198→export function onEvent(callback: EventCallback): () => void {
199→  eventListeners.add(callback);
200→  return () => {
201→    eventListeners.delete(callback);
202→  };
203→}
204→
205→/**
206→ * Send a tool response back to the backend (q:tool_response frame).
207→ * Used by frontend RPC handlers to respond to tool relay requests
208→ * received via q:event with event: "tool:request".
209→ */
210→export function sendToolResponse(requestId: string, result?: unknown, error?: string): boolean {
211→  const frame: Record<string, unknown> = {
212→    type: "q:tool_response",
213→    requestId,
214→  };
215→  if (error !== undefined) {
216→    frame.error = error;
217→  } else {
218→    frame.result = result;
219→  }
220→  return sendFrame(frame);
221→}
222→
223→/**
224→ * Register a callback for connection state changes.
225→ * Fires with `true` when connected, `false` when disconnected.
226→ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
227→ * Returns an unregister function.
228→ */
229→export function onConnectionChange(callback: (connected: boolean) => void): () => void {
230→  connectionChangeListeners.add(callback);
231→  return () => {
232→    connectionChangeListeners.delete(callback);
233→  };
234→}
235→
236→// ---- Internal ----
237→
238→async function openSocket(): Promise<void> {
239→  const port = await getBackendPort();
240→  const url = `ws://localhost:${port}/ws`;
241→
242→  ws = new WebSocket(url);
243→
244→  ws.onopen = () => {
245→    // Localhost connections are auto-authenticated by the backend.
246→    // Wait for the "connected" frame in onmessage.
247→  };
248→
249→  ws.onmessage = (evt) => {
250→    let msg: Record<string, unknown>;
251→    try {
252→      msg = JSON.parse(evt.data as string);
253→    } catch {
254→      return;
255→    }
256→
257→    const type = typeof msg.type === "string" ? msg.type : "";
258→
259→    match(type)
260→      .with("connected", () => {
261→        _connectionId = msg.connectionId as string;
262→        connected = true;
263→        connecting = false;
264→        reconnectAttempt = 0;
265→
266→        // Re-subscribe all active subscriptions (reconnect scenario)
267→        resubscribeAll();
268→
269→        // Notify hooks that connection is available so they can set up subscriptions
270→        notifyConnectionChange(true);
271→
272→        connectResolve?.();
273→        connectResolve = null;
274→        connectReject = null;
275→      })
276→      .with("ping", () => {
277→        sendFrame({ type: "pong" });
278→      })
279→      .with("q:snapshot", () => {
280→        const sub = subscriptions.get(msg.id as string);
281→        sub?.onSnapshot(msg.data);
282→      })
283→      .with("q:delta", () => {
284→        const sub = subscriptions.get(msg.id as string);
285→        sub?.onDelta?.(
286→          msg.upserted as unknown[] | undefined,
287→          msg.removed as string[] | undefined,
288→          msg.cursor as number | undefined
289→        );
290→      })
291→      .with("q:command_ack", () => {
292→        const pending = pendingCommands.get(msg.id as string);
293→        if (pending) {
294→          pendingCommands.delete(msg.id as string);
295→          pending.resolve({
296→            accepted: msg.accepted as boolean,
297→            commandId: msg.commandId as string | undefined,
298→            error: msg.error as string | undefined,
299→          });
300→        }
301→      })
302→      .with("q:event", () => {
303→        const event = msg.event as string;
304→        const data = msg.data;
305→        for (const cb of eventListeners) {
306→          try {
307→            cb(event, data);
308→          } catch (err) {
309→            console.error("[WS] Event listener error:", err);
310→          }
311→        }
312→      })
313→      .with("q:error", () => {
314→        console.warn("[WS] Query error:", msg.message, "for sub:", msg.id);
315→      })
316→      .otherwise(() => {
317→        // Ignore unknown frame types (q:response, q:mutate_result, etc.)
318→      });
319→  };
320→
321→  ws.onerror = () => {
322→    // onerror fires before onclose — actual cleanup happens in onclose
323→  };
324→
325→  ws.onclose = () => {
326→    const wasConnected = connected;
327→    connected = false;
328→    _connectionId = null;
329→    ws = null;
330→
331→    // Reject all pending commands immediately — they can't succeed without a connection
332→    for (const [_id, pending] of pendingCommands) {
333→      pending.reject(new Error("WebSocket disconnected"));
334→    }
335→    pendingCommands.clear();
336→
337→    if (connecting) {
338→      // Initial connection failed — reject the connect() promise
339→      connecting = false;
340→      connectReject?.(new Error("WebSocket connection failed"));
341→      connectResolve = null;
342→      connectReject = null;
343→    }
344→
345→    if (wasConnected) {
346→      notifyConnectionChange(false);
347→    }
348→
349→    // Only auto-reconnect if we had previously connected or have active subscriptions
350→    if (wasConnected || subscriptions.size > 0) {
351→      scheduleReconnect();
352→    }
353→  };
354→}
355→
356→/** Notify all connection change listeners. */
357→function notifyConnectionChange(state: boolean): void {
358→  for (const cb of connectionChangeListeners) {
359→    try {
360→      cb(state);
361→    } catch (err) {
362→      console.error("[WS] Connection change listener error:", err);
363→    }
364→  }
365→}
366→
367→function sendFrame(frame: Record<string, unknown>): boolean {
368→  if (ws && ws.readyState === WebSocket.OPEN) {
369→    try {
370→      ws.send(JSON.stringify(frame));
371→      return true;
372→    } catch {
373→      // Connection may have closed between readyState check and send
374→      console.warn(`[WS] Failed to send ${frame.type} frame: connection closed during send`);
375→      return false;
376→    }
377→  }
378→  console.warn(`[WS] Dropped ${frame.type} frame: WebSocket not connected`);
379→  return false;
380→}
381→
382→/** Re-subscribe all active subscriptions after reconnect. */
383→function resubscribeAll(): void {
384→  for (const sub of subscriptions.values()) {
385→    sendFrame({
386→      type: "q:subscribe",
387→      id: sub.id,
388→      resource: sub.resource,
389→      ...(sub.params ? { params: sub.params } : {}),
390→    });
391→  }
392→}
393→
394→/** Schedule a reconnection with exponential backoff. */
395→function scheduleReconnect(): void {
396→  if (reconnectTimer) return;
397→
398→  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
399→  reconnectAttempt++;
400→
401→  if (import.meta.env.DEV) {
402→    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
403→  }
404→
405→  reconnectTimer = setTimeout(() => {
406→    reconnectTimer = null;
407→    connecting = true;
408→
409→    // Set up resolve/reject so subscriptions get re-established
410→    connectResolve = null;
411→    connectReject = null;
412→
413→    openSocket().catch(() => {
414→      connecting = false;
415→      // onclose handler will schedule another reconnect
416→    });
417→  }, delay);
418→}
419→

  1→// src/shared/hooks/useWsToolRequest.ts
  2→//
  3→// Shared hook that listens for tool:request events arriving via the WebSocket
  4→// q:event channel. Dispatches to a handler callback and sends responses back
  5→// via q:tool_response.
  6→//
  7→// Multiple hook instances (useAgentRpcHandler, useBrowserRpcHandler,
  8→// useSimulatorRpcHandler) may be mounted simultaneously. A module-level Set
  9→// prevents duplicate responses to the same requestId.
 10→//
 11→// Usage in RPC handler hooks:
 12→//   useWsToolRequest((method, requestId, params, respond) => {
 13→//     match(method)
 14→//       .with("getDiff", () => handleGetDiff(params, respond))
 15→//       .otherwise(() => {}); // not mine, skip
 16→//   });
 17→
 18→import { useEffect, useLayoutEffect, useRef } from "react";
 19→import { onEvent, sendToolResponse } from "@/platform/ws";
 20→import type { ToolRequestEventData } from "@shared/types/query-protocol";
 21→
 22→/**
 23→ * Callback signature for WS tool request handlers.
 24→ *
 25→ * @param method - The RPC method name (e.g., "getDiff", "browserSnapshot")
 26→ * @param requestId - Unique ID for this request (used for response routing)
 27→ * @param params - Method parameters
 28→ * @param respond - Call with result to send success response
 29→ * @param respondError - Call with error string to send error response
 30→ */
 31→export type WsToolRequestHandler = (
 32→  method: string,
 33→  requestId: string,
 34→  params: Record<string, unknown>,
 35→  respond: (result: unknown) => void,
 36→  respondError: (error: string) => void
 37→) => void;
 38→
 39→/**
 40→ * Hook that listens for tool:request events via WebSocket and dispatches
 41→ * to the provided handler. The handler decides which methods to claim.
 42→ *
 43→ * Responses are sent via q:tool_response back through the WS connection.
 44→ */
 45→export function useWsToolRequest(handler: WsToolRequestHandler): void {
 46→  const handlerRef = useRef(handler);
 47→  useLayoutEffect(() => {
 48→    handlerRef.current = handler;
 49→  });
 50→
 51→  // Track handled requestIds to prevent duplicate responses across hook instances.
 52→  // Using a module-level Set so it's shared across all instances within the same page.
 53→  const handledRef = useRef(handledRequestIds);
 54→
 55→  useEffect(() => {
 56→    const unsubscribe = onEvent((event: string, data: unknown) => {
 57→      if (event !== "tool:request") return;
 58→
 59→      const payload = data as ToolRequestEventData;
 60→      if (!payload?.requestId || !payload?.method) return;
 61→
 62→      const { requestId, method, params } = payload;
 63→
 64→      // Check if already handled by another hook instance
 65→      if (handledRef.current.has(requestId)) return;
 66→
 67→      const respond = (result: unknown) => {
 68→        if (handledRef.current.has(requestId)) return; // guard double-response
 69→        if (!sendToolResponse(requestId, result)) return; // WS send failed — let other handlers try
 70→        handledRef.current.add(requestId);
 71→        scheduleCleanup(requestId);
 72→      };
 73→
 74→      const respondError = (error: string) => {
 75→        if (handledRef.current.has(requestId)) return;
 76→        if (!sendToolResponse(requestId, undefined, error)) return;
 77→        handledRef.current.add(requestId);
 78→        scheduleCleanup(requestId);
 79→      };
 80→
 81→      handlerRef.current(method, requestId, params, respond, respondError);
 82→    });
 83→
 84→    return unsubscribe;
 85→  }, []);
 86→}
 87→
 88→// ---- Deduplication state ----
 89→
 90→/** Module-level Set of requestIds that have been responded to.
 91→ *  Shared across all hook instances within the same page lifecycle. */
 92→const handledRequestIds = new Set<string>();
 93→
 94→/** Clean up old requestIds after 60s to prevent unbounded growth. */
 95→function scheduleCleanup(requestId: string): void {
 96→  setTimeout(() => {
 97→    handledRequestIds.delete(requestId);
 98→  }, 60_000);
 99→}
100→

  1→/**
  2→ * Workspace Query Hooks
  3→ * TanStack Query hooks for workspace-related data fetching
  4→ */
  5→
  6→import { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
  7→import { useMemo } from "react";
  8→import { produce } from "immer";
  9→import { WorkspaceService, type WorkspaceGitInfo } from "./workspace.service";
 10→import { RepoService } from "@/features/repository/api/repository.service";
 11→import { queryKeys } from "@/shared/api/queryKeys";
 12→import { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 13→import type { RepoGroup, DiffStats } from "../types";
 14→import type { PRStatus } from "@/shared/types";
 15→import { createOptimisticWorkspace, mergeWorkspaceDelta } from "../lib/workspace.utils";
 16→import { track } from "@/platform/analytics";
 17→
 18→/**
 19→ * Fetch workspaces grouped by repository.
 20→ *
 21→ * WS subscription pushes data directly into cache via q:snapshot.
 22→ * HTTP queryFn is fallback for initial load before WS connects.
 23→ * Event-driven invalidation via Tauri events also works (both paths coexist).
 24→ */
 25→export function useWorkspacesByRepo(state: string = "ready,initializing") {
 26→  useQuerySubscription("workspaces", {
 27→    queryKey: queryKeys.workspaces.byRepo(state),
 28→    params: { state },
 29→    mergeDelta: mergeWorkspaceDelta,
 30→  });
 31→
 32→  return useQuery({
 33→    queryKey: queryKeys.workspaces.byRepo(state),
 34→    queryFn: () => WorkspaceService.fetchByRepo(state),
 35→    staleTime: Infinity, // WS subscription keeps data fresh
 36→    refetchOnWindowFocus: false, // Subscription handles freshness
 37→  });
 38→}
 39→
 40→/**
 41→ * Fetch global stats.
 42→ *
 43→ * WS subscription pushes data directly into cache via q:snapshot.
 44→ * HTTP queryFn is fallback for initial load before WS connects.
 45→ */
 46→export function useStats() {
 47→  useQuerySubscription("stats", {
 48→    queryKey: queryKeys.stats.all,
 49→  });
 50→
 51→  return useQuery({
 52→    queryKey: queryKeys.stats.all,
 53→    queryFn: () => RepoService.fetchStats(),
 54→    staleTime: Infinity, // WS subscription keeps data fresh
 55→    refetchOnWindowFocus: false, // Subscription handles freshness
 56→  });
 57→}
 58→
 59→/**
 60→ * Fetch diff stats for a specific workspace
 61→ * Conditionally polls only when workspace is actively working.
 62→ *
 63→ * When `isWatched` is true (file watcher active via notify crate),
 64→ * polling is disabled — cache invalidation comes from fs:changed events.
 65→ * Falls back to 5s polling when not watched.
 66→ *
 67→ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 68→ * against incomplete worktrees during initialization. Running git diff on
 69→ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 70→ * cached for 30s, persisting as phantom diffs even after the workspace
 71→ * becomes ready. Guard here, not in the UI.
 72→ */
 73→export function useDiffStats(
 74→  workspaceId: string | null,
 75→  sessionStatus?: string | null,
 76→  workspace?: WorkspaceGitInfo,
 77→  isWatched: boolean = false,
 78→  workspaceState?: string | null
 79→) {
 80→  return useQuery({
 81→    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 82→    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!, workspace),
 83→    enabled: !!workspaceId && workspaceState === "ready",
 84→    staleTime: 30000,
 85→    // Events handle invalidation when watched; fall back to polling otherwise
 86→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 87→    refetchOnMount: "always",
 88→    refetchOnWindowFocus: true,
 89→  });
 90→}
 91→
 92→/**
 93→ * Fetch diff stats for all sidebar workspaces in bulk.
 94→ *
 95→ * Replaces per-item useDiffStats() in the sidebar (N hooks → 1 query).
 96→ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 97→ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 98→ * - Idle: no polling (staleTime 30s, refetch on window focus)
 99→ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
100→ *
101→ * Guard: state === "ready" — initializing worktrees have incomplete git state
102→ * (missing HEAD, partial index → garbage diffs like +500K/-1M). Setup script
103→ * diffs are fine — .gitignore handles them, and `git checkout -- .` in the
104→ * init pipeline resets any tracked-file mutations from bun install.
105→ */
106→export function useBulkDiffStats(repoGroups: RepoGroup[]) {
107→  const queryClient = useQueryClient();
108→
109→  const workspaceInfoMap = useMemo(() => {
110→    const map = new Map<string, WorkspaceGitInfo>();
111→    repoGroups.forEach((g) => {
112→      g.workspaces.forEach((w) => {
113→        if (w.state !== "ready") return;
114→        map.set(w.id, {
115→          root_path: w.root_path,
116→          slug: w.slug,
117→          workspace_path: w.workspace_path,
118→          git_target_branch: w.git_target_branch ?? undefined,
119→          git_default_branch: w.git_default_branch,
120→        });
121→      });
122→    });
123→    return map;
124→  }, [repoGroups]);
125→
126→  // Stable, de-duplicated IDs for query key — only ready workspaces.
127→  const workspaceIds = useMemo(() => {
128→    const ids = repoGroups.flatMap((g) =>
129→      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
130→    );
131→    return Array.from(new Set(ids)).sort();
132→  }, [repoGroups]);
133→
134→  // IDs of workspaces with active sessions — only these need polling.
135→  const workingIds = useMemo(() => {
136→    return repoGroups
137→      .flatMap((g) => g.workspaces)
138→      .filter((w) => w.state === "ready" && w.session_status === "working")
139→      .map((w) => w.id);
140→  }, [repoGroups]);
141→
142→  const hasWorkingWorkspaces = workingIds.length > 0;
143→
144→  return useQuery({
145→    queryKey: ["bulk-diff-stats", workspaceIds],
146→    enabled: workspaceIds.length > 0,
147→    staleTime: 30_000,
148→    placeholderData: keepPreviousData,
149→    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
150→    refetchOnMount: "always",
151→    refetchOnWindowFocus: true,
152→    queryFn: async () => {
153→      // Seed from per-workspace cache for workspaces we already have data for
154→      const results: Record<string, DiffStats> = {};
155→      for (const id of workspaceIds) {
156→        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
157→        if (cached) results[id] = cached;
158→      }
159→
160→      // Fetch: missing workspaces + working workspaces (need fresh data)
161→      const missingIds = workspaceIds.filter((id) => !(id in results));
162→      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
163→
164→      if (idsToFetch.length === 0) return results;
165→
166→      // Parallel batches of 15 — balances throughput vs resource pressure
167→      const BATCH_SIZE = 15;
168→      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
169→        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
170→        const settled = await Promise.allSettled(
171→          batch.map((id) => WorkspaceService.fetchDiffStats(id, workspaceInfoMap.get(id)))
172→        );
173→
174→        batch.forEach((id, j) => {
175→          if (settled[j].status === "fulfilled") {
176→            results[id] = settled[j].value;
177→            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
178→          }
179→        });
180→      }
181→
182→      return results;
183→    },
184→  });
185→}
