211→        truncated: result.truncated ?? false,
212→        totalCount: result.totalCount ?? result.files?.length ?? 0,
213→      };
214→    },
215→    enabled: !!workspaceId && workspaceState === "ready",
216→    staleTime: 30000,
217→    // Events handle invalidation when watched; fall back to polling otherwise
218→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
219→    refetchOnMount: "always",
220→    refetchOnWindowFocus: true,
221→  });
222→}
