400→      if (!isTauriAvailable()) {
401→        return [];
402→      }
403→      const { gitListBranches } = await import("@/platform/tauri/git");
404→      return await gitListBranches(workspacePath!);
405→    },
406→    enabled: !!workspacePath,
407→    staleTime: 30_000,
408→  });
409→}
