  5→
  6→import { apiClient } from "@/shared/api/client";
  7→import { ENDPOINTS } from "@/shared/config/api.config";
  8→import { isTauriAvailable } from "@/platform/tauri/invoke";
  9→import {
 10→  gitDiffStats,
 11→  gitDiffFiles,
 12→  gitDiffFile,
 13→  gitUncommittedFiles,
 14→  gitLastTurnFiles,
 15→} from "@/platform/tauri/git";
 16→import { dbGetWorkspacesByRepo } from "@/platform/tauri/db";
 17→import type { Workspace, RepoGroup, DiffStats, FileChange } from "../types";
 18→import type { PRStatus, GhCliStatus } from "@/shared/types";
 19→import type { NormalizedTask, ManifestResponse, TaskRunResponse } from "@shared/types/manifest";
 20→
 21→export type { NormalizedTask, ManifestResponse, TaskRunResponse };
 22→
 23→/** Workspace data needed for Tauri git commands (subset of Workspace) */
 24→export interface WorkspaceGitInfo {
 25→  root_path: string;
 26→  slug: string;
 27→  workspace_path?: string;
 28→  git_target_branch?: string;
 29→  git_default_branch?: string;
 30→}
 31→
 32→function getWorkspacePath(ws: WorkspaceGitInfo): string {
 33→  if (ws.workspace_path) return ws.workspace_path;
 34→  return `${ws.root_path}/.opendevs/${ws.slug}`;
 35→}
 36→
 37→export const WorkspaceService = {
 38→  /**
 39→   * Fetch workspaces grouped by repository.
 40→   * Uses Rust/rusqlite via Tauri IPC when available (~1ms),
 41→   * falls back to Node.js HTTP when in web mode (~50-200ms).
 42→   */
 43→  fetchByRepo: async (state?: string): Promise<RepoGroup[]> => {
 44→    if (isTauriAvailable()) {
 45→      try {
 46→        return await dbGetWorkspacesByRepo(state);
 47→      } catch {
 48→        // Rust DB failed — fall through to HTTP
 49→      }
 50→    }
 51→    const query = state ? `?state=${state}` : "";
 52→    return apiClient.get<RepoGroup[]>(`${ENDPOINTS.WORKSPACES_BY_REPO}${query}`);
 53→  },
 54→
 55→  /**
 56→   * Fetch diff statistics for a workspace.
 57→   * Uses Rust/libgit2 via Tauri IPC when available (5-20ms),
 58→   * falls back to Node.js HTTP when in web mode (50-200ms).
 59→   *
 60→   * Diffs are computed against origin/<parent_branch> (remote-first).
 61→   * Workspace creation fetches origin/<parent> before branching the worktree,
 62→   * so the merge-base is always a recent shared commit with upstream.
 63→   * See: src-tauri/src/git.rs::resolve_parent_branch for the resolution logic.
 64→   */
 65→  fetchDiffStats: async (id: string, workspace?: WorkspaceGitInfo): Promise<DiffStats> => {
 66→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
 67→      try {
 68→        return await gitDiffStats(
 69→          getWorkspacePath(workspace),
 70→          workspace.git_target_branch || "",
 71→          workspace.git_default_branch || ""
 72→        );
 73→      } catch {
 74→        // Rust git failed (e.g., worktree deleted) — fall through to HTTP
 75→      }
 76→    }
 77→    return apiClient.get<DiffStats>(ENDPOINTS.WORKSPACE_DIFF_STATS(id));
 78→  },
 79→
 80→  /**
 81→   * Fetch file changes for a workspace.
 82→   * Uses Rust/libgit2 via Tauri IPC when available,
 83→   * falls back to Node.js HTTP when in web mode.
 84→   *
 85→   * Returns { files, truncated, totalCount } — truncated is true when
 86→   * the diff contains more than 1000 files (capped to prevent UI freeze).
 87→   */
 88→  fetchDiffFiles: async (
 89→    id: string,
 90→    workspace?: WorkspaceGitInfo
 91→  ): Promise<{ files: FileChange[]; truncated?: boolean; totalCount?: number }> => {
 92→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
 93→      try {
 94→        const result = await gitDiffFiles(
 95→          getWorkspacePath(workspace),
 96→          workspace.git_target_branch || "",
 97→          workspace.git_default_branch || ""
 98→        );
 99→        return {
100→          files: result.files,
101→          truncated: result.truncated,
102→          totalCount: result.total_count,
103→        };
104→      } catch {
105→        // Rust git failed — fall through to HTTP
106→      }
107→    }
108→    const result = await apiClient.get<{
109→      files: FileChange[];
110→      truncated?: boolean;
111→      total_count?: number;
112→    }>(ENDPOINTS.WORKSPACE_DIFF_FILES(id));
113→    return {
114→      files: result.files,
115→      truncated: result.truncated ?? false,
116→      totalCount: result.total_count ?? result.files.length,
117→    };
118→  },
119→
120→  /**
121→   * Fetch diff for a specific file.
122→   * Uses Rust/libgit2 via Tauri IPC when available,
123→   * falls back to Node.js HTTP when in web mode.
124→   */
125→  fetchFileDiff: async (
126→    id: string,
127→    file: string,
128→    workspace?: WorkspaceGitInfo
129→  ): Promise<{ diff: string; oldContent: string | null; newContent: string | null }> => {
130→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
131→      try {
132→        const data = await gitDiffFile(
133→          getWorkspacePath(workspace),
134→          workspace.git_target_branch || "",
135→          workspace.git_default_branch || "",
136→          file
137→        );
138→        return {
139→          diff: data.diff ?? "",
140→          oldContent: data.old_content ?? null,
141→          newContent: data.new_content ?? null,
142→        };
143→      } catch {
144→        // Rust git failed — fall through to HTTP
145→      }
146→    }
147→    const data = await apiClient.get<{
148→      diff: string;
149→      old_content?: string | null;
150→      new_content?: string | null;
151→    }>(ENDPOINTS.WORKSPACE_DIFF_FILE(id, file));
152→    return {
153→      diff: data.diff ?? "",
154→      oldContent: data.old_content ?? null,
155→      newContent: data.new_content ?? null,
156→    };
157→  },
158→
159→  /**
160→   * Fetch uncommitted files (HEAD → workdir diff).
161→   * Tauri IPC only — no HTTP fallback needed.
162→   */
163→  fetchUncommittedFiles: async (workspace?: WorkspaceGitInfo): Promise<FileChange[]> => {
164→    if (!isTauriAvailable() || !workspace?.root_path || !workspace?.slug) {
165→      return [];
166→    }
167→    try {
168→      const files = await gitUncommittedFiles(getWorkspacePath(workspace));
169→      return files;
170→    } catch {
171→      return [];
172→    }
173→  },
174→
175→  /**
176→   * Fetch last-turn files (checkpoint → workdir diff).
177→   * Tauri IPC only — no HTTP fallback needed.
178→   */
179→  fetchLastTurnFiles: async (
180→    workspace?: WorkspaceGitInfo,
181→    sessionId?: string
182→  ): Promise<FileChange[]> => {
183→    if (!isTauriAvailable() || !workspace?.root_path || !workspace?.slug || !sessionId) {
184→      return [];
185→    }
186→    try {
187→      const files = await gitLastTurnFiles(getWorkspacePath(workspace), sessionId);
188→      return files;
189→    } catch {
190→      // No checkpoints exist yet — expected for new sessions
191→      return [];
192→    }
193→  },
194→
195→  /**
196→   * Create a new workspace
197→   */
198→  create: async (repositoryId: string): Promise<Workspace> => {
199→    return apiClient.post<Workspace>(ENDPOINTS.WORKSPACES, { repository_id: repositoryId });
200→  },
201→
202→  /**
