 1→import { createMiddleware } from 'hono/factory';
 2→import path from 'path';
 3→import { getDatabase } from '../lib/database';
 4→import { NotFoundError } from '../lib/errors';
 5→import { getWorkspaceForMiddleware } from '../db';
 6→import type { WorkspaceWithDetailsRow } from '../db';
 7→
 8→export interface WorkspaceContext {
 9→  workspace: WorkspaceWithDetailsRow;
10→  workspacePath: string;
11→}
12→
13→/**
14→ * Compute the filesystem path for a workspace.
15→ * All OpenDevs workspaces live at {root_path}/.opendevs/{slug}.
16→ */
17→export function computeWorkspacePath(ws: {
18→  root_path?: string | null;
19→  slug?: string | null;
20→}): string {
21→  if (!ws.root_path || !ws.slug) return '';
22→  return path.join(ws.root_path, '.opendevs', ws.slug);
23→}
24→
25→/**
26→ * Middleware that loads a workspace by :id param from the database.
27→ * Sets c.set('workspace') and c.set('workspacePath') on the Hono context.
28→ * Throws NotFoundError if workspace not found.
29→ */
30→export const withWorkspace = createMiddleware(async (c, next) => {
31→  const id = c.req.param('id')!;
32→  const db = getDatabase();
33→
34→  const workspace = getWorkspaceForMiddleware(db, id);
35→
36→  if (!workspace || !workspace.root_path || !workspace.slug) {
37→    throw new NotFoundError('Workspace not found');
38→  }
39→
40→  const workspacePath = computeWorkspacePath(workspace);
41→
42→  c.set('workspace', workspace);
43→  c.set('workspacePath', workspacePath);
44→
45→  await next();
46→});
