  1→// backend/src/services/agent/service.ts
  2→// Composition root for agent-server communication.
  3→//
  4→// Creates the AgentClient, wires the event handler with injected dependencies,
  5→// and exposes typed methods for other services to call. No circular imports —
  6→// this module imports from its dependencies, none of them import back.
  7→//
  8→// Dependency graph (all arrows point down, no cycles):
  9→//
 10→//   service (this file)
 11→//       ├── client              (WebSocket transport)
 12→//       ├── event-handler       (factory: createAgentEventHandler)
 13→//       └── tool-relay          (frontend RPC relay)
 14→//
 15→// Initialized once at startup in server.ts via agentService.init().
 16→
 17→import { AgentClient } from "./client";
 18→import { createAgentEventHandler } from "./event-handler";
 19→import { relay } from "./tool-relay";
 20→import type {
 21→  TurnStartRequest,
 22→  TurnStartResponse,
 23→  TurnRespondRequest,
 24→  SessionStopRequest,
 25→} from "../../../../shared/agent-events";
 26→
 27→// ---- Singleton ----
 28→
 29→let client: AgentClient | null = null;
 30→
 31→/** Initialize the agent service. Call once at startup. */
 32→export function init(agentServerUrl: string): void {
 33→  if (client) {
 34→    console.warn("[AgentService] Already initialized, skipping");
 35→    return;
 36→  }
 37→
 38→  client = new AgentClient({
 39→    url: agentServerUrl,
 40→
 41→    // Wire the event handler with respondToAgent injected — breaks the
 42→    // circular dependency that previously existed between these modules.
 43→    onEvent: createAgentEventHandler({
 44→      respondToAgent: (params) => respondToAgent(params),
 45→    }),
 46→
 47→    onConnected: (agents) => {
 48→      console.log(
 49→        `[AgentService] Connected, agents: [${agents.map((a) => a.type).join(", ")}]`
 50→      );
 51→    },
 52→    onDisconnected: () => {
 53→      console.log("[AgentService] Disconnected from agent-server");
 54→    },
 55→
 56→    // Relay sidecar's frontend-facing RPC requests (browser, sim, diff, plan)
 57→    onFrontendRpc: async (requestId, sessionId, method, params) => {
 58→      return relay({
 59→        type: "tool.request",
 60→        requestId,
 61→        sessionId,
 62→        method,
 63→        params,
 64→        timeoutMs: 120_000,
 65→      });
 66→    },
 67→  });
 68→
 69→  client.connect();
 70→}
 71→
 72→/** Gracefully shut down the agent client. */
 73→export function shutdown(): void {
 74→  client?.disconnect();
 75→  client = null;
 76→}
 77→
 78→// ---- Public API (typed wrappers) ----
 79→
 80→/** Forward a turn/start request to the agent-server. */
 81→export async function forwardTurn(
 82→  params: TurnStartRequest
 83→): Promise<TurnStartResponse> {
 84→  if (!client) throw new Error("Agent service not initialized");
 85→  return client.sendTurnStart(params);
 86→}
 87→
 88→/** Send a tool relay response back to the agent-server. */
 89→export async function respondToAgent(params: TurnRespondRequest): Promise<void> {
 90→  if (!client) throw new Error("Agent service not initialized");
 91→  return client.sendTurnRespond(params);
 92→}
 93→
 94→/** Stop a session on the agent-server. */
 95→export async function stopSession(params: SessionStopRequest): Promise<void> {
 96→  if (!client) throw new Error("Agent service not initialized");
 97→  return client.sendSessionStop(params);
 98→}
 99→
100→/** Check if the agent service is connected. */
101→export function isConnected(): boolean {
102→  return client?.isConnected() ?? false;
103→}
104→

  1→// backend/src/services/agent/event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent → backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Created via createAgentEventHandler() — a factory that injects the
  9→// respondToAgent dependency, breaking the circular import with service.ts.
 10→
 11→import { match } from "ts-pattern";
 12→import type { AgentEvent } from "../../../../shared/agent-events";
 13→import type { QueryResource } from "../../../../shared/types/query-protocol";
 14→import { invalidate } from "../query-engine";
 15→import { relay } from "./tool-relay";
 16→import {
 17→  persistAssistantMessage,
 18→  persistToolResultMessage,
 19→  persistMessageResult,
 20→  persistMessageCancelled,
 21→  persistSessionStarted,
 22→  persistSessionIdle,
 23→  persistSessionError,
 24→  persistSessionCancelled,
 25→  persistAgentSessionId,
 26→  type WriteResult,
 27→} from "./persistence";
 28→
 29→// ---- Types ----
 30→
 31→type RespondToAgentFn = (params: {
 32→  sessionId: string;
 33→  requestId: string;
 34→  result: unknown;
 35→}) => Promise<void>;
 36→
 37→export type AgentEventHandler = (event: AgentEvent) => void;
 38→
 39→// ---- Resource groups for invalidation ----
 40→
 41→const SESSION_RESOURCES: QueryResource[] = ["workspaces", "sessions", "session", "stats"];
 42→const MESSAGE_RESOURCES: QueryResource[] = ["messages", "session"];
 43→
 44→// ---- Helpers ----
 45→
 46→/** Persist an event and invalidate subscriptions if the write succeeded. */
 47→function persistAndInvalidate(
 48→  result: WriteResult<unknown>,
 49→  resources: QueryResource[],
 50→  sessionId: string,
 51→): void {
 52→  if (result.ok) {
 53→    invalidate(resources, { sessionIds: [sessionId] });
 54→  }
 55→}
 56→
 57→// ---- Factory ----
 58→
 59→/**
 60→ * Create an agent event handler with injected dependencies.
 61→ *
 62→ * The respondToAgent function is injected to break the circular dependency
 63→ * between this module and service.ts. The composition root (service.ts)
 64→ * provides the concrete implementation: client.sendTurnRespond().
 65→ */
 66→export function createAgentEventHandler(deps: {
 67→  respondToAgent: RespondToAgentFn;
 68→}): AgentEventHandler {
 69→  const { respondToAgent } = deps;
 70→
 71→  return function handleAgentEvent(event: AgentEvent): void {
 72→    match(event)
 73→      // ── Session lifecycle ─────────────────────────────────────────────
 74→      .with({ type: "session.started" }, (e) => {
 75→        console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 76→        persistAndInvalidate(persistSessionStarted(e), SESSION_RESOURCES, e.sessionId);
 77→      })
 78→      .with({ type: "session.idle" }, (e) => {
 79→        console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 80→        persistAndInvalidate(persistSessionIdle(e), SESSION_RESOURCES, e.sessionId);
 81→      })
 82→      .with({ type: "session.error" }, (e) => {
 83→        console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 84→        persistAndInvalidate(persistSessionError(e), SESSION_RESOURCES, e.sessionId);
 85→      })
 86→      .with({ type: "session.cancelled" }, (e) => {
 87→        console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 88→        persistAndInvalidate(persistSessionCancelled(e), SESSION_RESOURCES, e.sessionId);
 89→      })
 90→
 91→      // ── Messages ──────────────────────────────────────────────────────
 92→      .with({ type: "message.assistant" }, (e) => {
 93→        console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
 94→        persistAndInvalidate(persistAssistantMessage(e), MESSAGE_RESOURCES, e.sessionId);
 95→      })
 96→      .with({ type: "message.tool_result" }, (e) => {
 97→        console.log(`[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`);
 98→        persistAndInvalidate(persistToolResultMessage(e), MESSAGE_RESOURCES, e.sessionId);
 99→      })
100→      .with({ type: "message.result" }, (e) => {
101→        console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
102→        persistMessageResult(e);
103→      })
104→      .with({ type: "message.cancelled" }, (e) => {
105→        console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
106→        persistAndInvalidate(
107→          persistMessageCancelled(e),
108→          ["messages", "sessions", "session", "stats"],
109→          e.sessionId,
110→        );
111→      })
112→
113→      // ── Interaction requests ──────────────────────────────────────────
114→      .with({ type: "request.opened" }, (e) => {
115→        console.log(`[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`);
116→      })
117→      .with({ type: "request.resolved" }, (e) => {
118→        console.log(`[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`);
119→      })
120→
121→      // ── Tool relay ────────────────────────────────────────────────────
122→      .with({ type: "tool.request" }, (e) => {
123→        console.log(`[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`);
124→        void relayToolRequest(e, respondToAgent);
125→      })
126→
127→      // ── Metadata ──────────────────────────────────────────────────────
128→      .with({ type: "agent.session_id" }, (e) => {
129→        console.log(`[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`);
130→        persistAndInvalidate(persistAgentSessionId(e), SESSION_RESOURCES, e.sessionId);
131→      })
132→
133→      .exhaustive();
134→  };
135→}
136→
137→// ---- Tool relay internal ----
138→
139→async function relayToolRequest(
140→  event: AgentEvent & { type: "tool.request" },
141→  respondToAgent: RespondToAgentFn,
142→): Promise<void> {
143→  const { sessionId, requestId, method } = event;
144→
145→  try {
146→    const result = await relay(event);
147→    await respondToAgent({ sessionId, requestId, result });
148→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
149→  } catch (err) {
150→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
151→    try {
152→      await respondToAgent({
153→        sessionId,
154→        requestId,
155→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
156→      });
157→    } catch (respondErr) {
158→      console.error(`[AgentEvent] Failed to send error response to agent: requestId=${requestId}`, respondErr);
159→    }
160→  }
161→}
