  1→import { Hono } from 'hono';
  2→import { cors } from 'hono/cors';
  3→import { createNodeWebSocket } from '@hono/node-ws';
  4→import { errorHandler } from './middleware/error-handler';
  5→import { remoteGateMiddleware } from './middleware/remote-gate';
  6→import { authMiddleware } from './middleware/remote-auth';
  7→import { validateDeviceToken } from './services/remote-auth.service';
  8→import {
  9→  addConnection,
 10→  removeConnection,
 11→  handleProtocolMessage,
 12→} from './services/ws.service';
 13→import { removeSubs as removeQuerySubs } from './services/query-engine';
 14→import { getRelayStatus } from './services/relay.service';
 15→import { isLocalhost, getClientIp } from './lib/network';
 16→import healthRoutes from './routes/health';
 17→import workspaceRoutes from './routes/workspaces';
 18→import workspaceDiffRoutes from './routes/workspaces.diff';
 19→import workspacePrRoutes from './routes/workspaces.pr';
 20→import workspaceDesignRoutes from './routes/workspaces.design';
 21→import sessionRoutes from './routes/sessions';
 22→import repoRoutes from './routes/repos';
 23→import agentConfigRoutes from './routes/agent-config';
 24→import settingsRoutes from './routes/settings';
 25→import statsRoutes from './routes/stats';
 26→import onboardingRoutes from './routes/onboarding';
 27→import authRoutes from './routes/remote-auth';
 28→
 29→export function createApp() {
 30→  const app = new Hono();
 31→  const { upgradeWebSocket, injectWebSocket } = createNodeWebSocket({ app });
 32→
 33→  // Middleware — order matters:
 34→  // 1. Remote gate rejects non-localhost when remote access is disabled
 35→  // 2. CORS headers for browser requests
 36→  // 3. Auth validates Bearer tokens for remote clients (localhost exempt)
 37→  app.use('*', remoteGateMiddleware);
 38→  app.use('*', cors());
 39→  app.use('/api/*', authMiddleware);
 40→
 41→  // Mount route groups
 42→  // Note: Sidecar routes removed - agent runtime now managed by sidecar-v2 (Rust-spawned)
 43→  app.route('/api', healthRoutes);
 44→  app.route('/api', authRoutes);
 45→  app.route('/api', workspaceRoutes);
 46→  app.route('/api', workspaceDiffRoutes);
 47→  app.route('/api', workspacePrRoutes);
 48→  app.route('/api', workspaceDesignRoutes);
 49→  app.route('/api', sessionRoutes);
 50→  app.route('/api', repoRoutes);
 51→  app.route('/api', agentConfigRoutes);
 52→  app.route('/api', settingsRoutes);
 53→  app.route('/api', statsRoutes);
 54→  app.route('/api', onboardingRoutes);
 55→
 56→  // Relay status endpoint
 57→  app.get('/api/relay/status', (c) => {
 58→    return c.json(getRelayStatus());
 59→  });
 60→
 61→  // WebSocket route for remote access.
 62→  // Localhost connections are auto-authenticated. Remote clients must send
 63→  // { type: "initialize", token: "..." } as their first message.
 64→  app.get('/ws', upgradeWebSocket((c) => {
 65→    const ip = getClientIp(c);
 66→    const isLocal = isLocalhost(ip);
 67→    let connectionId: string | null = null;
 68→
 69→    return {
 70→      onOpen(_evt, ws) {
 71→        if (isLocal) {
 72→          // Desktop/localhost connections skip token auth
 73→          connectionId = addConnection(ws, null);
 74→          ws.send(JSON.stringify({ type: 'connected', connectionId }));
 75→        }
 76→        // Remote clients stay unauthenticated until initialize message
 77→      },
 78→
 79→      onMessage(evt, ws) {
 80→        let msg: Record<string, unknown>;
 81→        try {
 82→          const raw = typeof evt.data === 'string' ? evt.data : String(evt.data);
 83→          msg = JSON.parse(raw);
 84→        } catch {
 85→          return; // Ignore malformed messages
 86→        }
 87→
 88→        // Unauthenticated remote client — must initialize first
 89→        if (!connectionId) {
 90→          if (msg.type === 'initialize' && typeof msg.token === 'string') {
 91→            const device = validateDeviceToken(msg.token);
 92→            if (device) {
 93→              connectionId = addConnection(ws, device.id);
 94→              ws.send(JSON.stringify({ type: 'connected', connectionId }));
 95→            } else {
 96→              ws.send(JSON.stringify({ type: 'error', message: 'Invalid token' }));
 97→              ws.close(4001, 'Invalid token');
 98→            }
 99→          } else {
100→            ws.send(JSON.stringify({ type: 'error', message: 'Must send initialize with token' }));
101→            ws.close(4001, 'Not authenticated');
102→          }
103→          return;
104→        }
105→
106→        // Authenticated — handle protocol messages (shared with relay virtual connections)
107→        handleProtocolMessage(connectionId, msg);
108→      },
109→
110→      onClose() {
111→        if (connectionId) {
112→          removeQuerySubs(connectionId);
113→          removeConnection(connectionId);
114→          connectionId = null;
115→        }
116→      },
117→    };
118→  }));
119→
120→  // Centralized error handling
121→  app.onError(errorHandler);
122→
123→  return { app, injectWebSocket };
124→}
