export function backfillWorkspaceStatus(db: Database.Database): void {
  const needsBackfill = db.prepare(
    "SELECT COUNT(*) as c FROM workspaces WHERE status = 'in-progress' AND state = 'archived'"
  ).get() as { c: number };
  if (needsBackfill.c === 0) return; // Already backfilled or no archived workspaces

  db.prepare("UPDATE workspaces SET status = 'done' WHERE state = 'archived' AND archive_commit IS NOT NULL AND status = 'in-progress'").run();
  db.prepare("UPDATE workspaces SET status = 'canceled' WHERE state = 'archived' AND archive_commit IS NULL AND status = 'in-progress'").run();
  db.prepare("UPDATE workspaces SET status = 'in-review' WHERE pr_url IS NOT NULL AND state = 'ready' AND status = 'in-progress'").run();
}
