362→export function getStats(db: Database.Database): StatsRow {
363→  const now = Date.now();
364→  if (cachedStats && now - cachedAt < STATS_TTL_MS) return cachedStats;
365→  cachedStats = db.prepare(`
366→    SELECT
367→      (SELECT COUNT(*) FROM workspaces) as workspaces,
368→      (SELECT COUNT(*) FROM workspaces WHERE state = 'ready') as workspaces_ready,
369→      (SELECT COUNT(*) FROM workspaces WHERE state = 'archived') as workspaces_archived,
370→      (SELECT COUNT(*) FROM repositories) as repositories,
371→      (SELECT COUNT(*) FROM sessions) as sessions,
372→      (SELECT COUNT(*) FROM sessions WHERE status = 'idle') as sessions_idle,
373→      (SELECT COUNT(*) FROM sessions WHERE status = 'working') as sessions_working,
374→      (SELECT COUNT(*) FROM messages) as messages
375→  `).get() as StatsRow;
376→  cachedAt = now;
377→  return cachedStats;
378→}
379→
380→/** Reset the in-memory stats cache (for testing). */
381→export function resetStatsCache(): void {
382→  cachedStats = null;
383→  cachedAt = 0;
384→}
