453→// ---- Mutation Dispatch ----
454→
455→function runMutation(action: string, params: QueryParams): unknown {
456→  const typedAction = toMutationName(action);
457→
458→  return match(typedAction)
459→    .with("archiveWorkspace", () => {
460→      const db = getDatabase();
461→      const workspaceId = readStringParam(params, "workspaceId");
462→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
463→
464→      const workspace = getWorkspaceRaw(db, workspaceId);
465→      if (!workspace) throw new Error("Workspace not found");
466→
467→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
468→      invalidate(["workspaces", "stats"]);
469→      return { success: true };
470→    })
471→    .with("updateWorkspaceTitle", () => {
472→      const db = getDatabase();
473→      const workspaceId = readStringParam(params, "workspaceId");
474→      const title = readStringParam(params, "title");
475→      if (!workspaceId || title === undefined) {
476→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
477→      }
478→
479→      const workspace = getWorkspaceRaw(db, workspaceId);
480→      if (!workspace) throw new Error("Workspace not found");
481→
482→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
483→      invalidate(["workspaces"]);
484→      return { success: true };
485→    })
486→    .exhaustive();
487→}
