489→// ---- Message Delta Push ----
490→
491→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
492→  const sessionId = readStringParam(params, "sessionId");
493→  if (!sessionId) return;
494→
495→  const cursorKey = `${connectionId}:${subId}`;
496→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
497→
498→  try {
499→    const db = getDatabase();
500→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
501→
502→    if (newMessages.length === 0) return;
503→
504→    const maxSeq = newMessages[newMessages.length - 1].seq;
505→    messageCursors.set(cursorKey, maxSeq);
506→
507→    sendFrame(connectionId, {
508→      type: "q:delta",
509→      id: subId,
510→      upserted: newMessages,
511→      cursor: maxSeq,
512→    });
513→  } catch (err) {
514→    console.error(`[QueryEngine] Message delta push failed:`, err);
515→  }
516→}
