518→// ---- Helpers ----
519→
520→function sendFrame(connectionId: string, frame: QServerFrame): void {
521→  const conn = getConnection(connectionId);
522→  if (!conn) return;
523→  try {
524→    conn.ws.send(JSON.stringify(frame));
525→  } catch {
526→    // Connection may have closed
527→  }
528→}
