530→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
531→  return {
532→    id: requireString(msg.id, "id"),
533→    resource: requireString(msg.resource, "resource"),
534→    params: getParams(msg.params),
535→  };
536→}
537→
538→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
539→  return {
540→    id: requireString(msg.id, "id"),
541→  };
542→}
543→
544→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
545→  return {
546→    id: requireString(msg.id, "id"),
547→    action: requireString(msg.action, "action"),
548→    params: getParams(msg.params),
549→  };
550→}
551→
552→function getParams(value: unknown): QueryParams {
553→  if (value == null) return {};
554→  if (isRecord(value)) return value;
555→  throw new Error("Frame params must be an object");
556→}
557→
558→function requireString(value: unknown, field: string): string {
559→  if (typeof value !== "string") {
560→    throw new Error(`Frame requires string ${field}`);
561→  }
562→  return value;
563→}
564→
565→function getFrameId(msg: QueryParams): string {
566→  return typeof msg.id === "string" ? msg.id : "unknown";
567→}
568→
569→function isRecord(value: unknown): value is QueryParams {
570→  return typeof value === "object" && value !== null && !Array.isArray(value);
571→}
572→
573→function readStringParam(params: QueryParams, key: string): string | undefined {
574→  const value = params[key];
575→  return typeof value === "string" ? value : undefined;
576→}
577→
578→function readNumberParam(params: QueryParams, key: string): number | undefined {
579→  const value = params[key];
580→  return typeof value === "number" ? value : undefined;
581→}
582→
583→function isQueryResource(value: string): value is QueryResource {
584→  return (QUERY_RESOURCES as readonly string[]).includes(value);
585→}
586→
587→function toQueryResource(value: string): QueryResource {
588→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
589→  return value;
590→}
591→
592→function isMutationName(value: string): value is MutationName {
593→  return (MUTATION_NAMES as readonly string[]).includes(value);
594→}
595→
596→function toMutationName(value: string): MutationName {
597→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
598→  return value;
599→}
600→
601→function parseCommandFrame(msg: QueryParams): CommandFrameInput {
602→  return {
603→    id: requireString(msg.id, "id"),
604→    command: requireString(msg.command, "command"),
605→    params: getParams(msg.params),
606→  };
607→}
608→
609→function isCommandName(value: string): value is CommandName {
610→  return (COMMAND_NAMES as readonly string[]).includes(value);
611→}
612→
613→function toCommandName(value: string): CommandName {
614→  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
615→  return value;
616→}
