 59→/**
 60→ * Fetch diff stats for a specific workspace
 61→ * Conditionally polls only when workspace is actively working.
 62→ *
 63→ * When `isWatched` is true (file watcher active via notify crate),
 64→ * polling is disabled — cache invalidation comes from fs:changed events.
 65→ * Falls back to 5s polling when not watched.
 66→ *
 67→ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 68→ * against incomplete worktrees during initialization. Running git diff on
 69→ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 70→ * cached for 30s, persisting as phantom diffs even after the workspace
 71→ * becomes ready. Guard here, not in the UI.
 72→ */
 73→export function useDiffStats(
 74→  workspaceId: string | null,
 75→  sessionStatus?: string | null,
 76→  workspace?: WorkspaceGitInfo,
 77→  isWatched: boolean = false,
 78→  workspaceState?: string | null
 79→) {
 80→  return useQuery({
 81→    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 82→    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!, workspace),
 83→    enabled: !!workspaceId && workspaceState === "ready",
 84→    staleTime: 30000,
 85→    // Events handle invalidation when watched; fall back to polling otherwise
 86→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 87→    refetchOnMount: "always",
 88→    refetchOnWindowFocus: true,
 89→  });
 90→}
 91→
 92→/**
 93→ * Fetch diff stats for all sidebar workspaces in bulk.
 94→ *
 95→ * Replaces per-item useDiffStats() in the sidebar (N hooks → 1 query).
 96→ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 97→ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 98→ * - Idle: no polling (staleTime 30s, refetch on window focus)
 99→ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
100→ *
101→ * Guard: state === "ready" — initializing worktrees have incomplete git state
102→ * (missing HEAD, partial index → garbage diffs like +500K/-1M). Setup script
103→ * diffs are fine — .gitignore handles them, and `git checkout -- .` in the
104→ * init pipeline resets any tracked-file mutations from bun install.
105→ */
106→export function useBulkDiffStats(repoGroups: RepoGroup[]) {
107→  const queryClient = useQueryClient();
108→
109→  const workspaceInfoMap = useMemo(() => {
110→    const map = new Map<string, WorkspaceGitInfo>();
111→    repoGroups.forEach((g) => {
112→      g.workspaces.forEach((w) => {
113→        if (w.state !== "ready") return;
114→        map.set(w.id, {
115→          root_path: w.root_path,
116→          slug: w.slug,
117→          workspace_path: w.workspace_path,
118→          git_target_branch: w.git_target_branch ?? undefined,
119→          git_default_branch: w.git_default_branch,
120→        });
121→      });
122→    });
123→    return map;
124→  }, [repoGroups]);
125→
126→  // Stable, de-duplicated IDs for query key — only ready workspaces.
127→  const workspaceIds = useMemo(() => {
128→    const ids = repoGroups.flatMap((g) =>
129→      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
130→    );
131→    return Array.from(new Set(ids)).sort();
132→  }, [repoGroups]);
133→
134→  // IDs of workspaces with active sessions — only these need polling.
135→  const workingIds = useMemo(() => {
136→    return repoGroups
137→      .flatMap((g) => g.workspaces)
138→      .filter((w) => w.state === "ready" && w.session_status === "working")
139→      .map((w) => w.id);
140→  }, [repoGroups]);
141→
142→  const hasWorkingWorkspaces = workingIds.length > 0;
143→
144→  return useQuery({
145→    queryKey: ["bulk-diff-stats", workspaceIds],
146→    enabled: workspaceIds.length > 0,
147→    staleTime: 30_000,
148→    placeholderData: keepPreviousData,
149→    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
150→    refetchOnMount: "always",
151→    refetchOnWindowFocus: true,
152→    queryFn: async () => {
153→      // Seed from per-workspace cache for workspaces we already have data for
154→      const results: Record<string, DiffStats> = {};
155→      for (const id of workspaceIds) {
156→        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
157→        if (cached) results[id] = cached;
158→      }
159→
160→      // Fetch: missing workspaces + working workspaces (need fresh data)
161→      const missingIds = workspaceIds.filter((id) => !(id in results));
162→      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
163→
164→      if (idsToFetch.length === 0) return results;
165→
166→      // Parallel batches of 15 — balances throughput vs resource pressure
167→      const BATCH_SIZE = 15;
168→      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
169→        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
170→        const settled = await Promise.allSettled(
171→          batch.map((id) => WorkspaceService.fetchDiffStats(id, workspaceInfoMap.get(id)))
172→        );
173→
174→        batch.forEach((id, j) => {
175→          if (settled[j].status === "fulfilled") {
176→            results[id] = settled[j].value;
177→            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
178→          }
179→        });
180→      }
181→
182→      return results;
183→    },
184→  });
185→}
