285→/**
286→ * Fetch PR status for a workspace.
287→ *
288→ * Gated on gh CLI being installed + authenticated (like Codex).
289→ * Polls every 30s while agent is working (to detect PR creation),
290→ * 60s while CI is pending post-session (CI runs 2-15min after push),
291→ * stops polling otherwise.
292→ */
293→export function usePRStatus(
294→  workspaceId: string | null,
295→  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
296→) {
297→  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
298→  return useQuery({
299→    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
300→    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
301→    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
302→    staleTime: 10_000,
303→    refetchInterval: (query) => {
304→      // While agent is working: poll every 30s to detect PR creation/updates.
305→      if (sessionStatus === "working") return 30_000;
306→
307→      // After agent stops: CI checks typically run 2-15min. Poll every 60s
308→      // while CI is pending so the user sees updates without manual refresh.
309→      const data = query.state.data as PRStatus | null | undefined;
310→      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
311→
312→      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
313→      return false;
314→    },
315→    refetchOnWindowFocus: true,
316→  });
317→}
