338→/**
339→ * Create workspace mutation with optimistic update.
340→ *
341→ * Flow:
342→ * 1. User clicks "+" → placeholder workspace appears instantly in sidebar
343→ * 2. Backend creates workspace (state = "initializing"), returns it
344→ * 3. onSuccess replaces placeholder with real data, triggers refetch
345→ * 4. Workspace progress events + terminal invalidation catch the ready transition
346→ */
347→export function useCreateWorkspace() {
348→  const queryClient = useQueryClient();
349→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
350→
351→  return useMutation({
352→    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),
353→
354→    onMutate: async (repositoryId: string) => {
355→      await queryClient.cancelQueries({ queryKey });
356→
357→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
358→
359→      // Inject a placeholder workspace into the matching repo group
360→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
361→        if (!old) return old;
362→        return produce(old, (draft) => {
363→          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
364→          if (repoGroup) {
365→            repoGroup.workspaces.unshift(
366→              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
367→            );
368→          }
369→        });
370→      });
371→
372→      return { previousData };
373→    },
374→
375→    onError: (_err, _repositoryId, context) => {
376→      if (context?.previousData) {
377→        queryClient.setQueryData(queryKey, context.previousData);
378→      }
379→    },
380→
381→    onSuccess: (_data, repositoryId) => {
382→      track("workspace_created", { repository_id: repositoryId });
383→    },
384→
385→    onSettled: () => {
386→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
387→    },
388→  });
389→}
